extern char *s_bss;
extern char *e_bss;
extern int virtio_init(void);
extern void virtio_blk_dump_state(void);

static inline void clear_bss() { memset(s_bss, 0, e_bss - s_bss); }
volatile bool sched_enabled = false;

static void vfs_tree_dentry(struct dentry *dentry, int depth)
{
	if (depth > 5 || !dentry || !dentry->d_inode) return;

	struct inode *inode = dentry->d_inode;
	if (!S_ISDIR(inode->i_mode)) return;

	struct file tmpfile;
	memset(&tmpfile, 0, sizeof(tmpfile));
	tmpfile.f_inode = inode;
	tmpfile.f_op = inode->i_fop;
	tmpfile.f_pos = 0;

	if (!tmpfile.f_op || !tmpfile.f_op->readdir) return;

	void *buf = kzalloc_page();
	if (!buf) return;

	char indent[64];
	for (int i = 0; i < depth * 2 && i < 62; i++) indent[i] = ' ';
	indent[depth * 2] = '\0';

	loff_t pos = 0;
	ssize_t nr;

	while ((nr = tmpfile.f_op->readdir(&tmpfile, buf, PAGE_SIZE, &pos)) > 0) {
		u8 *p = (u8 *)buf;
		u8 *end = (u8 *)buf + nr;
		while (p < end) {
			struct linux_dirent64 *de = (struct linux_dirent64 *)p;
			if (de->d_reclen == 0) break;
			p += de->d_reclen;

			if (de->d_name[0] == '.' && (de->d_name[1] == '\0' ||
			    (de->d_name[1] == '.' && de->d_name[2] == '\0')))
				continue;

			int nlen = 0;
			while (de->d_name[nlen]) nlen++;

			if (de->d_type == DT_DIR)
				infof("%s[DIR]  %s", indent, de->d_name);
			else
				infof("%s[FILE] %s", indent, de->d_name);

			if (de->d_type == DT_DIR) {
				struct dentry *child =
				    vfs_lookup_one_len(dentry, de->d_name, nlen);
				if (!IS_ERR_OR_NULL(child)) {
					vfs_tree_dentry(child, depth + 1);
					dentry_put(child);
				}
			}
		}
	}

	kfree_page(buf);
}

static void vfs_tree(void)
{
	struct dentry *root = vfs_get_root();
	if (!root) {
		infof("[vfs_tree] no root dentry!");
		return;
	}
	infof("=== filesystem tree ===");
	vfs_tree_dentry(root, 0);
	infof("=== end of tree ===");
	uart_out_flush();
}

void main(u64 hartid, void *_)
{
	if (hartid == 0) {
		clear_bss();
		INIT_LIST_HEAD(&proc_list);
		init_cpu(hartid);
		infof("NoobKernel booting on cpu: %d", r_tp());
		print_pm_layout();
		uart_out_flush();

		pm_init();
		infof("pm_init done");
		plic_init();
		infof("plic_init done");
		trap_init();
		infof("trap_init done");
		uart_init();
		infof("uart_init done");
		plic_set_priority(10, 1);
		plic_set_threshold('S', 0, 0);
		plic_enable('S', 0, 10);
		kvminit();
		infof("kvminit done");
		init_runq();
		infof("init_runq done");
		blk_init();
		infof("blk_init done");
		bcache_init();
		infof("bcache_init done");
		virtio_init();
		infof("virtio_init done");
		uart_out_flush();

		vfs_init();
		infof("vfs_init done");
		ramfs_init();
		infof("ramfs_init done");

	#ifdef COMPETITION
		infof("=== virtio state before mount ===");
		virtio_blk_dump_state();
		ext4_init();
		infof("ext4_init done");
		infof("mounting ext4 root...");
		uart_out_flush();
		int ret = vfs_mount_root(get_fs("ext4"),
					MKDEV(BLK_MAJOR_VIRTIO, 0));
		infof("vfs_mount_root returned %d", ret);
		if (ret == 0) {
			struct dentry *root = vfs_get_root();
			infof("vfs_get_root() = %p", root);
			if (root) {
				infof("root: name='%s' inode=%p mode=%o f_op=%p",
				      root->d_name.name, root->d_inode,
				      root->d_inode ? root->d_inode->i_mode : 0,
				      root->d_inode ? root->d_inode->i_fop : NULL);
			}
			vfs_tree();
		} else {
			infof("MOUNT FAILED, skip tree");
		}
	#else
		vfs_mount_root(ramfs_get_fs_type(), 0);

		vfs_create("/hello.txt", 0644);
		struct file *f = vfs_open("/hello.txt", O_RDWR);
		if (!IS_ERR(f)) {
			const char *msg = "Hello from NoobKernel!\n";
			vfs_write(f, msg, strlen(msg));
			vfs_close(f);
			infof("created /hello.txt in ramfs");
		}
	#endif
		uart_out_flush();

		/* start timer after all boot init to avoid conflicts */
		timer_init();
		infof("timer_init done");
		init_user_process();
		infof("init process created");
		uart_out_flush();

		// watchdog_enabled = true;
		watchdog_ticks = 0;
		sched_enabled = true;
		context_switch_to(&thiscpu()->idle.ctx);
		sched_yield();
	}
	while (1) {
		arch_wait_for_interrupt();
	}
}

