/* forward: from mm/pagetable.c — avoid double-include of PTE macros */
extern pte_t *va2pte(pagetable_t pagetable, uintptr_t va, bool alloc);

extern void virtio_blk_isr(void);

extern char kernelvec[], trampoline[], uservec[], userret[];
extern bool sched_enabled;

extern void handle_timer(void);
extern void handle_external(void);
extern void handle_ipi(void);

void handle_external(void)
{
	u64 hartid = arch_hart_id();
	u32 irqno = plic_claim('S', hartid);

	if (irqno == 0)
		return;

	switch (irqno) {
	case 1:
	case 2:
	case 3:
	case 4:
	case 5:
	case 6:
	case 7:
	case 8:
		if (irqno == 1)
			virtio_blk_isr();
		break;
	case 10: uart_isr(); break;
	default:
		warnf("handle_external: unknown irq %d", irqno);
		break;
	}

	plic_complete('S', hartid, irqno);
}

void intr_off(void)
{
	struct cpu *c = thiscpu();

	if (c->intr_depth == 0) {
		c->intr_state = arch_irq_state_read();
		arch_irq_state_write(c->intr_state & ~ARCH_STATUS_IRQ_ENABLE);
	}
	c->intr_depth++;
}

void intr_on(void)
{
	struct cpu *c = thiscpu();

	if (c->intr_depth <= 0)
		panic("intr_on: mismatch");

	c->intr_depth--;
	if (c->intr_depth == 0)
		arch_irq_state_write(c->intr_state);
}

void restore_intr(u64 old)
{
	struct cpu *c = thiscpu();

	c->intr_depth = 0;
	c->intr_state = old;
	arch_irq_state_write(old);
}

static void set_kerneltrap(void)
{
	arch_trap_vector_write((uintptr_t)kernelvec & ~0x3ULL);
}

int trap_init(void)
{
	set_kerneltrap();
	arch_irq_mask_write(arch_irq_mask_read() | ARCH_IRQ_EXTERNAL_ENABLE |
			    ARCH_IRQ_TIMER_ENABLE |
			    ARCH_IRQ_SOFTWARE_ENABLE);
	arch_irq_state_write(arch_irq_state_read() | ARCH_STATUS_IRQ_ENABLE);
	return 0;
}

void kerneltrap(struct ktrapframe *ktf)
{
	u64 scause = ktf->scause;
	u64 sepc = ktf->sepc;

	if (!arch_trap_cause_is_interrupt(scause)) {
		switch (scause) {
		case IllegalInstruction:
			panic("kernel illegal instruction at %p", sepc);
		case LoadPageFault:
		case StorePageFault:
			panic("kernel page fault at %p, stval=%p", sepc,
			      arch_fault_addr_read());
		case UserEnvCall:
			panic("kernel ecall at %p (should not happen)", sepc);
		default:
			panic("kernel exception: scause=%lx, sepc=%p, stval=%p",
			      scause, sepc, arch_fault_addr_read());
		}
	}

	switch (arch_trap_interrupt_id(scause)) {
	case SupervisorSoft:
		break;
	case SupervisorTimer:
		handle_timer();
		break;
	case SupervisorExternal:
		handle_external();
		break;
	default:
		panic("unknown kernel interrupt: irq=%d (scause=%lx)",
		      arch_trap_interrupt_id(scause), scause);
	}

	if (sched_enabled && thiscpu()->need_resched)
		sched_yield();
}

void usertrap(void)
{
	struct proc *p = thiscpu()->proc;
	u64 cause;

	if (!p || !p->tf)
		panic("usertrap: no current user process");

	arch_trap_vector_write((uintptr_t)kernelvec & ~0x3ULL);
	cause = arch_trap_cause_read();
	p->tf->epc = arch_exception_pc_read();

	if (!arch_trap_cause_is_interrupt(cause)) {
		switch (cause) {
		case UserEnvCall:
			syscall_dispatch();
			/* errorf("usertrap: back from syscall nr=%d ret=%d "
			 *       "epc=%p sp=%p",
			 *      p->tf->a7, p->tf->a0,
			 *      p->tf->epc, p->tf->sp);
			**/
			break;
		case IllegalInstruction:
			panic("user illegal instruction at %p", p->tf->epc);
		case LoadPageFault:
		case StorePageFault: {
			uintptr_t faddr = arch_fault_addr_read();
			/* try to read PTE at fault address from kernel side */
			pte_t *pte = va2pte(p->pagetable, faddr, false);
			if (pte && (*pte & PTE_V)) {
				panic("user %s page fault at %p, stval=%p "
				      "PTE=%p flags=%c%c%c%c%c",
				      cause == LoadPageFault ? "LOAD" : "STORE",
				      p->tf->epc, faddr, *pte,
				      (*pte & PTE_R) ? 'R' : '-',
				      (*pte & PTE_W) ? 'W' : '-',
				      (*pte & PTE_X) ? 'X' : '-',
				      (*pte & PTE_U) ? 'U' : '-',
				      (*pte & PTE_M) ? 'M' : '-');
			} else if (pte) {
				panic("user %s page fault at %p, stval=%p "
				      "PTE=%p (no V flag)",
				      cause == LoadPageFault ? "LOAD" : "STORE",
				      p->tf->epc, faddr, *pte);
			} else {
				panic("user %s page fault at %p, stval=%p "
				      "(no PTE — intermediate table missing)",
				      cause == LoadPageFault ? "LOAD" : "STORE",
				      p->tf->epc, faddr);
			}
		}
		case InstructionPageFault:
			panic("user instruction page fault at %p", p->tf->epc);
		case Breakpoint:
			kthread_exit(0);
			break;
		default:
			panic("user exception: cause=%lx, epc=%p", cause,
			      p->tf->epc);
		}
		usertrapret();
		return;
	}

	switch (arch_trap_interrupt_id(cause)) {
	case SupervisorSoft:
		break;
	case SupervisorTimer:
		handle_timer();
		break;
	case SupervisorExternal:
		handle_external();
		break;
	default:
		panic("unknown user interrupt: irq=%d (cause=%lx)",
		      arch_trap_interrupt_id(cause), cause);
	}

	if (sched_enabled && thiscpu()->need_resched)
		sched_yield();

	usertrapret();
}

void usertrapret(void)
{
	struct proc *p = thiscpu()->proc;
	uintptr_t trampoline_userret;
	void (*userret_fn)(uintptr_t, u64);

	if (!p || !p->tf)
		panic("usertrapret: no current user process");

	/* Stack overflow guard check: magic at kstack bottom */
	if (p->kstack) {
		u32 *guard = (u32 *)p->kstack;
		if (guard[0] != 0xDEADBEEF || guard[1] != 0xDEADBEEF)
			panic("KSTACK OVERFLOW pid=%d comm=%s "
			      "magic=%x %x", p->pid, p->comm,
			      guard[0], guard[1]);
	}

	/* Trapframe integrity check for pid=2 (autoinit parent).
	 * epc must be in user code (0x10000-0x20000), sp in user
	 * stack (0x7FFF8000-0x80000000).  Any deviation = corruption. */
	if (p->pid == 2) {
		uintptr_t epc = p->tf->epc;
		uintptr_t sp  = p->tf->sp;
		if (epc < 0x10000 || epc > 0x20000 ||
		    sp < 0x7FFF8000 || sp > 0x80000000)
			panic("TRAPFRAME CORRUPTED pid=2: "
			      "epc=%p sp=%p ra=%p a0=%p a7=%p",
			      epc, sp, p->tf->ra, p->tf->a0, p->tf->a7);
	}

	p->tf->kernel_satp = ARCH_MMU_ROOT_MAKE(kpagetable);
	p->tf->kernel_sp = (uintptr_t)p->kstack + KSTACK_SIZE;
	p->tf->kernel_trap = (uintptr_t)usertrap;
	p->tf->kernel_hartid = arch_cpu_id();

	arch_trap_vector_write(TRAMPOLINE + ((uintptr_t)uservec -
					     (uintptr_t)trampoline));
	arch_user_return_prepare(p->tf->epc);

	uart_out_flush();

	/* 确保 sret 能正确重开中断（防御 spinlock intr_on 覆盖 SPIE）
	 * 与 Linux arch/riscv/kernel/entry.S:ret_from_exception 等价 */
	w_sstatus(r_sstatus() | SSTATUS_SPIE);

	trampoline_userret = TRAMPOLINE + ((uintptr_t)userret -
					   (uintptr_t)trampoline);
	userret_fn = (void (*)(uintptr_t, u64))trampoline_userret;


	userret_fn(TRAPFRAME, ARCH_MMU_ROOT_MAKE(p->pagetable));
	panic("usertrapret: returned from trampoline");
}

