struct {
	struct list_head queue;
	spinlock_t lock;
} __attribute__((aligned(CACHE_LINE_SIZE))) runq[CPU_NUM];

void init_runq()
{
	for (int i = 0; i < CPU_NUM; i++) {
		INIT_LIST_HEAD(&runq[i].queue);
		runq[i].lock = SPINLOCK_INITIALIZER("runq");
	}
}

bool is_runq_empty(int hartid) { return list_empty(&runq[hartid].queue); }

void enqueue_proc(int hartid, struct proc *p)
{
	spinlock_acquire(&runq[hartid].lock);
	list_add_tail(&p->runq, &runq[hartid].queue);
	spinlock_release(&runq[hartid].lock);
}

struct proc *dequeue_proc(int hartid)
{
	spinlock_acquire(&runq[hartid].lock);
	if (is_runq_empty(hartid)) {
		spinlock_release(&runq[hartid].lock);
		return NULL;
	}
	struct list_head *lh = runq[hartid].queue.next;
	list_del(lh);
	spinlock_release(&runq[hartid].lock);
	struct proc *p = container_of(lh, struct proc, runq);
	return p;
}

void sched_yield()
{
	struct cpu *c = thiscpu();
	struct proc *p = c->proc;
	if (p) {
		// errorf("sched_yield: pid=%d state=%d", p->pid, p->state);
		switch (p->state) {
		case PROC_RUNNING:
			p->state = PROC_RUNNABLE;
			enqueue_proc(r_tp(), p);
			break;
		default:
			break;
		}
	} else
		panic("null proc pointer in %s", __func__);

	thiscpu()->proc = NULL;
	context_switch_yield(p);
}

void context_switch_yield(struct proc *old)
{
	struct cpu *c = thiscpu();
	struct proc *next;

	next = dequeue_proc(r_tp());
	if (!next) {
		next = &c->idle;
		// errorf("ctx_switch: pid=%d → IDLE (runq empty)", old->pid);
	} else {
		// errorf("ctx_switch: pid=%d → pid=%d state=%d",
		//        old->pid, next->pid, next->state);
	}
	spinlock_acquire(&next->lock);
	if (next != &c->idle) {
		next->state = PROC_RUNNING;
	}
	c->proc = next;
	spinlock_release(&next->lock);
	context_switch(&old->ctx, &next->ctx);
}

void sleep(void *chan, spinlock_t *lock)
{
	struct proc *p = thiscpu()->proc;
	if (!p)
		panic("sleep: no current proc");

	// errorf("sleep: pid=%d on chan=%p state=%d", p->pid, chan, p->state);

	if (lock) {
		spinlock_release(lock);
	}

	p->chan = chan;
	p->state = PROC_SLEEPING;
	sched_yield();

	// errorf("sleep: pid=%d WOKE UP state=%d", p->pid, p->state);

	p->chan = NULL;

	if (lock) {
		spinlock_acquire(lock);
	}
}

void wakeup(void *chan)
{
	// errorf("wakeup: scanning for chan=%p", chan);
	spinlock_acquire(&proc_list_lock);
	struct list_head *pos, *n;
	list_for_each_safe(pos, n, &proc_list)
	{
		struct proc *p = list_entry(pos, struct proc, proc_list);
		if (p->state == PROC_SLEEPING && p->chan == chan) {
			spinlock_acquire(&p->lock);
			if (p->state == PROC_SLEEPING && p->chan == chan) {
				// errorf("wakeup: found pid=%d chan=%p",
				//        p->pid, p->chan);
				p->state = PROC_RUNNABLE;
				enqueue_proc(r_tp(), p);
			}
			spinlock_release(&p->lock);
		}
	}
	spinlock_release(&proc_list_lock);
}

