extern void kthread_start(void);

struct proc *kthread_create(int (*fn)(void *), void *arg, const char *name)
{
	struct proc *p = alloc_proc();
	if (!p)
		return NULL;

	// 1. 设置基本信息
	if (name)
		strncpy(p->comm, name, sizeof(p->comm));
	p->pid = alloc_pid();
	p->tgid = p->pid;
	p->pagetable = kpagetable; // 共享内核页表
	p->lock = SPINLOCK_INITIALIZER(name);
	// 2. 分配内核栈（1 页足够）
	p->kstack = buddy_alloc(PAGE_SIZE * 4);
	if (!p->kstack) {
		free_proc(p);
		return NULL;
	}
	/* stack overflow guard */
	*(u32 *)p->kstack = 0xDEADBEEF;
	*(u32 *)((u8 *)p->kstack + 4) = 0xDEADBEEF;

	// 3. 初始化上下文
	// 栈顶对齐（RISC-V ABI 要求 16 字节对齐）
	u64 stack_top = (u64)p->kstack + KSTACK_SIZE;
	stack_top &= ~0xF; // 16-byte align

	// 设置初始 context
	p->ctx.ra = (u64)kthread_start; // 返回地址 = kthread_start
	p->ctx.sp = stack_top;

	// 将 fn 和 arg 压入栈中，供 kthread_start 使用
	u64 *args = (u64 *)(stack_top - 16);
	args[0] = (u64)fn;
	args[1] = (u64)arg;

	// 调整 sp，为参数留出空间（kthread_start 会读取）
	p->ctx.sp = stack_top - 16;

	// 4. 设置状态为 RUNNABLE
	p->state = PROC_RUNNABLE;

	// 5. 加入调度队列（当前 CPU）
	enqueue_proc(r_tp(), p);

	return p;
}

void kthread_exit(int ret_code)
{
	struct proc *p = thiscpu()->proc;
	if (!p)
		panic("kthread_exit: no current proc");

	if (p->pid == 2) {
		infof("init process exited, shutting down");
		arch_shutdown();
	}

	// infof("kthread %s exited with code %d", p->comm, ret_code);

	p->exit_code = ret_code;
	if (p->child_tidp) {
		u64 zero = 0;
		copyout(p->pagetable, p->child_tidp, &zero, sizeof(zero));
	}

	/*
	 * Free user page table and all mapped physical pages.
	 * Safe to do here: the page table is not used for
	 * kernel stack operations.
	 */
	if (0) {
		pagetable_destroy(p->pagetable);
		p->pagetable = NULL;
	}

	/*
	 * kstack and tf are freed by the parent in wait4,
	 * because we are still running on this kstack.
	 */

	p->state = PROC_ZOMBIE;

	// errorf("kthread_exit: pid=%d parent=%p parent_state=%d",
	//        p->pid, p->parent,
	//        p->parent ? p->parent->state : -1);

	if (p->parent)
		wakeup(p->parent);

	// errorf("kthread_exit: after wakeup parent_state=%d",
	//        p->parent ? p->parent->state : -1);

	sched_yield();
	panic("kthread_exit returned");
}

extern char _binary_shell_bin_start[];
extern char _binary_shell_bin_end[];

struct elf_info {
	uintptr_t entry;
	uintptr_t min_va;
	uintptr_t max_va;
};

static int load_elf_mem(pagetable_t pagetable, const void *elf, size_t size,
			struct elf_info *info)
{
	const struct elf64_ehdr *ehdr = (const struct elf64_ehdr *)elf;

	if (size < sizeof(struct elf64_ehdr))
		return -1;
	if (ehdr->e_ident[0] != ELFMAG0 || ehdr->e_ident[1] != ELFMAG1 ||
	    ehdr->e_ident[2] != ELFMAG2 || ehdr->e_ident[3] != ELFMAG3)
		return -1;
	if (ehdr->e_ident[EI_CLASS] != ELFCLASS64)
		return -1;
	if (ehdr->e_ident[EI_DATA] != ELFDATA2LSB)
		return -1;
	if (ehdr->e_type != ET_EXEC && ehdr->e_type != ET_DYN)
		return -1;
	if (ehdr->e_machine != EM_RISCV)
		return -1;

	info->entry = ehdr->e_entry;
	info->min_va = VM_END;
	info->max_va = 0;

	const struct elf64_phdr *phdrs =
	    (const struct elf64_phdr *)((const char *)elf + ehdr->e_phoff);

	for (int i = 0; i < ehdr->e_phnum; i++) {
		const struct elf64_phdr *phdr = &phdrs[i];

		if (phdr->p_type != PT_LOAD)
			continue;

		uintptr_t va_start = PAGE_ALIGN_DOWN(phdr->p_vaddr);
		uintptr_t va_end = PAGE_ALIGN_UP(phdr->p_vaddr + phdr->p_memsz);

		if (va_start < info->min_va)
			info->min_va = va_start;
		if (va_end > info->max_va)
			info->max_va = va_end;

		int perm = PTE_V | PTE_U;
		if (phdr->p_flags & PF_R)
			perm |= PTE_R;
		if (phdr->p_flags & PF_W)
			perm |= PTE_W;
		if (phdr->p_flags & PF_X)
			perm |= PTE_X;

		size_t npages = (va_end - va_start) / PAGE_SIZE;
		for (size_t j = 0; j < npages; j++) {
			uintptr_t va = va_start + j * PAGE_SIZE;
			void *page = kzalloc_page();
			if (!page)
				return -1;

			const char *src = (const char *)elf + phdr->p_offset;
			uintptr_t data_start = (va > phdr->p_vaddr)
			    ? va
			    : phdr->p_vaddr;
			uintptr_t data_end =
			    (va + PAGE_SIZE <
			     phdr->p_vaddr + phdr->p_filesz)
			    ? (va + PAGE_SIZE)
			    : (phdr->p_vaddr + phdr->p_filesz);
			if (data_end > data_start) {
				size_t copy_len = data_end - data_start;
				off_t file_off =
				    data_start - phdr->p_vaddr;
				memcpy(page + (data_start - va),
				       src + file_off, copy_len);
			}

			if (mappages(pagetable, va, (uintptr_t)page, 1,
				     perm | PTE_M)) {
				kfree_page(page);
				return -1;
			}
		}
	}
	return 0;
}

