static void tf_overlap_check(void *addr, size_t sz, const char *who) {
	if (!watched_tf_pa) return;
	uintptr_t a = (uintptr_t)addr, t = (uintptr_t)watched_tf_pa;
	if (a < t + PAGE_SIZE && a + sz > t)
		panic("%s: %p-%p overlaps TRAPFRAME %p!",
		      who, addr, a + sz, watched_tf_pa);
