	return ptr;
}

void *kcalloc(size_t nitems, size_t size)
{
	if (nitems && size > SIZE_MAX / nitems) {
		warnf("kcalloc overflow");
		return NULL; // overflow!
	}
	return kzalloc(nitems * size);
}

void *krealloc(void *ptr, size_t size)
{
	if (!ptr)
