	}

	/* Debug: catch pages with both flags (double-allocation) */
	if ((page->flags & (PM_SLAB | PM_BUDDY)) == (PM_SLAB | PM_BUDDY))
		panic("kfree: page %p has both PM_SLAB and PM_BUDDY!", addr);

	if (page->flags & PM_SLAB)
		kmem_cache_free(addr);
	else if (page->flags & PM_BUDDY)
		buddy_free(addr);
	else
		warnf("trying free an invalid ptr: %p", addr);
}

/* page allocator: bypass slab, use buddy directly (Linux 5.1 style) */
void *kzalloc_page(void)
{
	void *addr = buddy_alloc_page();
	if (addr)
		memset(addr, 0, PAGE_SIZE);
	return addr;
}

void kfree_page(void *addr)
{
	buddy_free_page(addr);
}

#include <misc/log.h>
#include <mm/pagetable.h>
#include <mm/vm.h>
#include <mm/kalloc.h>

extern char s_text[];
extern char e_text[];
extern char s_rodata[];
extern char e_rodata[];
extern char s_data[];
extern char e_data[];
extern char s_bss[];
extern char e_bss[];
extern char ekernel[];
extern char trampoline[];

pagetable_t kpagetable;

uintptr_t va2pa(pagetable_t pagetable, uintptr_t va)
{
	uintptr_t page = walkaddr(pagetable, va);
	if (page == 0)
		return 0;
	return page | (va & 0xFFFULL);
}

static inline int kmappages(pagetable_t pagetable, uintptr_t va, uintptr_t pa,
			    size_t npages, int perm)
{
	return mappages(pagetable, va, pa, npages, (perm & ~PTE_U) | PTE_V);
}

static inline void devminit()
{
	if (kmappages(kpagetable, 0, 0, PM_START / PAGE_SIZE, PTE_R | PTE_W)) {
		panic("mapping device memory");
	}
}

void kvminit()
{
	kpagetable = pagetable_create();

	// 设备地址空间
	devminit();

	// 内核text段
	if (kmappages(kpagetable, KVM(s_text), (uintptr_t)s_text,
		      ((uintptr_t)e_text - (uintptr_t)s_text) / PAGE_SIZE,
		      PTE_R | PTE_X)) {
		panic("mapping kernel text seg");
	}

	// 内核rodata段
	if (kmappages(kpagetable, KVM(s_rodata), (uintptr_t)s_rodata,
		      ((uintptr_t)e_rodata - (uintptr_t)s_rodata) / PAGE_SIZE,
		      PTE_R)) {
		panic("mapping kernel rodata seg");
	}

	// 内核data&bss段
	if (kmappages(kpagetable, KVM(s_data), (uintptr_t)s_data,
		      ((uintptr_t)e_bss - (uintptr_t)s_data) / PAGE_SIZE,
		      PTE_R | PTE_W)) {
		panic("mapping kernel data&bss seg");
	}

	// 跳板页
	if (kmappages(kpagetable, TRAMPOLINE, (uintptr_t)trampoline, 1,
		      PTE_R | PTE_X | PTE_G)) {
		panic("mapping kernel trampoline");
	}

	// 信号返回跳板页
	void *sigpage = kzalloc_page();
	if (!sigpage)
		panic("kvminit: no mem for signal trampoline");
	*(u32 *)sigpage = 0x00000073;
	if (kmappages(kpagetable, SIGNAL_TRAMPOLINE, (uintptr_t)sigpage, 1,
		      PTE_R | PTE_X | PTE_G)) {
		panic("mapping signal trampoline");
	}

	// 剩余内存
	if (kmappages(kpagetable, KVM(ekernel), (uintptr_t)ekernel,
		      (PM_END - (uintptr_t)ekernel) / PAGE_SIZE, PTE_R | PTE_W)) {
		panic("mapping remaining memory");
	}

	w_satp(MAKE_SATP(kpagetable));
	sfence_vma();
	infof("enable pageing at %p", r_satp());
}

#include <misc/errno.h>
#include <misc/log.h>
#include <misc/string.h>
#include <mm/kalloc.h>
#include <mm/pagetable.h>
#include <mm/vm.h>
#include <misc/align.h>

pte_t *va2pte(pagetable_t pagetable, uintptr_t va, bool alloc)
{
	for (int level = 2; level > 0; level--) {
		pte_t *pte = &pagetable[PX(level, va)];
		if (*pte & PTE_V) {
			// 如果已有下一级页表，则进入下一级寻找
			pagetable = (pagetable_t)PTE2PA(*pte);
		} else {
			// 如果下一级页表没创建且：
			//    需要创建：分配一页内存存放下一级页表
			//    无需创建：直接返回NULL表示未找到
			if (!alloc || (pagetable = kzalloc_page()) == NULL)
				return NULL;
			*pte = PA2PTE(pagetable) | PTE_V;
		}
	}
	return &pagetable[PX(0, va)];
}

uintptr_t walkaddr(pagetable_t pagetable, uintptr_t va)
{
	pte_t *pte;
	uintptr_t pa;

	if (va >= VM_END)
		return 0;

	pte = va2pte(pagetable, va, false);
	if (pte == 0)
		return 0;
	if ((*pte & PTE_M) == 0)
		return 0;
	pa = PTE2PA(*pte);
	return pa;
}

pagetable_t pagetable_create() { return kzalloc_page(); }

static void pagetable_destroy_level(pagetable_t pagetable, int level)
{
	if (pagetable == NULL)
		return;

	if (level > 0) {
		for (int i = 0; i < PTES_PER_PAGE; i++) {
			pte_t pte = pagetable[i];
			if (pte & PTE_V) {
				pagetable_t child =
				    (pagetable_t)PTE2PA(pte);
				pagetable_destroy_level(child, level - 1);
			}
		}
	} else {
		/* level == 0: free leaf physical pages */
		for (int i = 0; i < PTES_PER_PAGE; i++) {
			pte_t pte = pagetable[i];
			if (pte & PTE_M) {
				void *leaf = (void *)PTE2PA(pte);
				kfree_page(leaf);
			}
		}
	}

	kfree_page(pagetable);
}

void pagetable_destroy(pagetable_t pagetable)
{
	if (pagetable == NULL)
		return;
	pagetable_destroy_level(pagetable, 2); // Sv39 根页表是 level 2
}

int mappages(pagetable_t pagetable, uintptr_t va, uintptr_t pa, size_t npages,
	     int perm)
{
	if (pagetable == NULL)
		return -EINVAL;
	if (!PAGE_ALIGNED(va) || !PAGE_ALIGNED(pa))
		return -EINVAL;
	if (npages == 0)
		return 0;
	if (va + npages * PAGE_SIZE > VM_END)
		return -ERANGE;
	if (pa + npages * PAGE_SIZE > PM_END)
		return -ERANGE;
	pte_t *pte;
	perm &= 0x3f;
	for (size_t i = 0; i < npages; i++) {
		pte = va2pte(pagetable, va + i * PAGE_SIZE, true);
		if (!pte)
			return -ENOMEM;
		if (*pte & PTE_M) {
			return -EADDRINUSE;
		}
		*pte = PA2PTE(pa + i * PAGE_SIZE) | perm | PTE_M;
	}
	return 0;
}

int unmappages(pagetable_t pagetable, uintptr_t vm, size_t npages)
{
	pte_t *pte;
	uintptr_t start = PAGE_ALIGN_DOWN(vm);
	uintptr_t end = start + npages * PAGE_SIZE;
	for (uintptr_t a = start; a < end; a += PAGE_SIZE) {
		if ((pte = va2pte(pagetable, a, false)) == NULL)
			continue;
		if(*pte & PTE_M){
			kfree_page((void *)PTE2PA(*pte));
			*pte = 0;
		}else{
			debugf("trying unmap not mapped page");
		}
	}
	return 0;
}

#include <misc/errno.h>
#include <mm/kalloc.h>
#include <mm/pagetable.h>
#include <mm/vm.h>
#include <mm/vma.h>

struct vma *vma_create(uintptr_t start, size_t length, int perm, int type)
{
	if (start < VM_START || start + length >= VM_END ||
	    type < VMA_TYPE_START || type > VMA_TYPE_END)
		return NULL;
	struct vma *vma = kzalloc(sizeof(struct vma));
	if (!vma)
		return NULL;

	vma->start = start;
	vma->length = length;
	vma->perm = perm;
	vma->type = type;
	return vma;
}

// 销毁一个 VMA（释放结构体内存，不解除页表映射）
void vma_destroy(struct vma *vma)
{
	list_del(&vma->list);
	kfree(vma);
}

// 查找包含 va 的 VMA（链表有序，可提前终止）
struct vma *vma_find(struct proc *proc, uintptr_t va)
{
	struct list_head *pos;
	struct vma *vma;
	list_for_each(pos, &proc->vma)
	{
		vma = list_entry(pos, struct vma, list);
		if (va < vma->start)
			break; // 后续 VMA 起始更大，无需继续
		if (va < vma->start + vma->length)
			return vma;
	}
	return NULL;
}

// 插入 VMA（仅检查重叠，不合并）
int vma_insert(struct proc *proc, struct vma *new_vma)
{
	struct list_head *pos;
	list_for_each(pos, &proc->vma)
	{
		struct vma *vma = list_entry(pos, struct vma, list);
		// 检查重叠：[a, a+len) 与 [b, b+len) 重叠 ⇨ !(a+len <= b ||
		// b+len <= a)
		if (!(new_vma->start + new_vma->length <= vma->start ||
		      vma->start + vma->length <= new_vma->start)) {
			return -EEXIST; // 重叠，不允许
		}
		if (vma->start > new_vma->start)
			break;
	}
	list_add_tail(&new_vma->list, pos);
	return 0;
}

// 删除完全匹配的 VMA（不支持拆分，调用者需保证范围对齐整个 VMA）
int vma_remove(struct proc *proc, uintptr_t start, size_t length)
{
	struct vma *vma = vma_find(proc, start);
	if (!vma || vma->start != start || vma->length != length)
		return -ENOENT; // 要求精确匹配（简化逻辑）

	vma_unmap_pages(proc, start, length);
	list_del(&vma->list);
	vma_destroy(vma);
	return 0;
}

// 建立映射（延迟分配：pa=0 ⇒ PTE_V=0, PTE_M=1）
int vma_map_pages(struct proc *proc, struct vma *vma)
{
	return mappages(proc->pagetable, vma->start, 0, vma->length / PAGE_SIZE,
			vma->perm);
}

// 解除页表映射
int vma_unmap_pages(struct proc *proc, uintptr_t start, size_t length)
{
	return unmappages(proc->pagetable, start, length / PAGE_SIZE);
}

#include <mm/bcache.h>
#include <hal/blk.h>
#include <misc/string.h>
#include <misc/log.h>
#include <sync/barrier.h>

static struct {
	struct buf bufs[BCACHE_SIZE];
	struct list_head hash_table[BCACHE_HASH_SIZE];
	struct list_head lru_list;
	spinlock_t lock;
} bcache;

static inline u32 bcache_hash(dev_t dev, u64 blockno)
{
	return (dev + blockno) % BCACHE_HASH_SIZE;
}

void bcache_init(void)
{
	spinlock_acquire(&bcache.lock);

	INIT_LIST_HEAD(&bcache.lru_list);
	for (int i = 0; i < BCACHE_HASH_SIZE; i++) {
		INIT_LIST_HEAD(&bcache.hash_table[i]);
	}

	for (int i = 0; i < BCACHE_SIZE; i++) {
		struct buf *b = &bcache.bufs[i];
		b->dev = 0;
		b->blockno = 0;
		b->refcnt = 0;
		b->dirty = false;
		b->valid = false;
		b->lock = SPINLOCK_INITIALIZER("bcache_buf");
		INIT_LIST_HEAD(&b->hash);
		INIT_LIST_HEAD(&b->lru);
		list_add(&b->lru, &bcache.lru_list);
	}

	spinlock_release(&bcache.lock);
	infof("bcache initialized: %d buffers, %d hash buckets", BCACHE_SIZE,
	      BCACHE_HASH_SIZE);
}

static struct buf *bcache_lookup(dev_t dev, u64 blockno)
{
	u32 hash = bcache_hash(dev, blockno);
	struct list_head *head = &bcache.hash_table[hash];

	struct buf *b;
	list_for_each_entry(b, head, hash)
	{
		if (b->dev == dev && b->blockno == blockno) {
			return b;
		}
	}
	return NULL;
}

static struct buf *bcache_evict(void)
{
	struct buf *b;
	list_for_each_entry_reverse(b, &bcache.lru_list, lru)
	{
		if (b->refcnt == 0) {
			if (b->dirty) {
				blk_write(b->dev, b->blockno, b->data, 1);
				b->dirty = false;
			}
			list_del(&b->hash);
			b->valid = false;
			return b;
		}
	}
	return NULL;
}

static struct buf *bcache_get(dev_t dev, u64 blockno)
{
	spinlock_acquire(&bcache.lock);

	struct buf *b = bcache_lookup(dev, blockno);
	if (b) {
		b->refcnt++;
		list_del(&b->lru);
		list_add(&b->lru, &bcache.lru_list);
		spinlock_release(&bcache.lock);
		spinlock_acquire(&b->lock);
		return b;
	}

	b = bcache_evict();
	if (!b) {
		panic("bcache: no free buffers");
	}

	b->dev = dev;
	b->blockno = blockno;
	b->refcnt = 1;
	b->valid = false;
	b->dirty = false;

	u32 hash = bcache_hash(dev, blockno);
	list_add(&b->hash, &bcache.hash_table[hash]);
	list_del(&b->lru);
	list_add(&b->lru, &bcache.lru_list);

	spinlock_release(&bcache.lock);
	spinlock_acquire(&b->lock);

	return b;
}

struct buf *bread(dev_t dev, u64 blockno)
{
	struct buf *b = bcache_get(dev, blockno);

	if (!b->valid) {
		blk_read(dev, blockno, b->data, 1);
		b->valid = true;
	}

	return b;
}

void bwrite(struct buf *b)
{
	if (!b->valid) {
		warnf("bwrite: buffer not valid");
		return;
	}

	b->dirty = true;
	blk_write(b->dev, b->blockno, b->data, 1);
	b->dirty = false;
}

void brelse(struct buf *b)
{
	spinlock_release(&b->lock);

	spinlock_acquire(&bcache.lock);
	b->refcnt--;
	if (b->refcnt == 0) {
		list_del(&b->lru);
		list_add(&b->lru, &bcache.lru_list);
	}
	spinlock_release(&bcache.lock);
}

void bcache_flush(dev_t dev)
{
	spinlock_acquire(&bcache.lock);

	struct buf *b;
	list_for_each_entry(b, &bcache.lru_list, lru)
	{
		if (b->dev == dev && b->dirty) {
			spinlock_acquire(&b->lock);
			blk_write(b->dev, b->blockno, b->data, 1);
			b->dirty = false;
			spinlock_release(&b->lock);
		}
	}

	spinlock_release(&bcache.lock);
}

void bcache_sync(void)
{
	spinlock_acquire(&bcache.lock);

	struct buf *b;
	list_for_each_entry(b, &bcache.lru_list, lru)
	{
		if (b->dirty) {
			spinlock_acquire(&b->lock);
			blk_write(b->dev, b->blockno, b->data, 1);
			b->dirty = false;
			spinlock_release(&b->lock);
		}
	}

	spinlock_release(&bcache.lock);
}

/* syscall_dispatch: 系统调用分发器
 *   从 trapframe.a7 读取系统调用号，分发给对应实现函数
 *   返回值写入 trapframe.a0，并推进 epc 跳过 ecall 指令
 *   不返回的函数（exit/exec/shutdown）自行处理 epc
 *
 * fdget / fdput / fdnum: Linux 风格的 fd 生命周期配对
 *   fdget:  从 trapframe arg_n 读取 fd → 查表 → 递增 file 引用计数
 *   fdput:  释放 fdget 获取的引用
 *   fdnum:  仅提取 fd 号（用于 sys_close 等仅需 fd 号无需查表的场景）
 */
#include <syscall/syscall.h>
#include <trap/trap.h>
#include <task/proc.h>
#include <task/sched.h>
#include <fs/fd_table.h>
#include <fs/file.h>
#include <misc/errno.h>
#include <misc/string.h>
#include <arch/cpu.h>

int fdget(int arg_n, struct file **fp)
{
	int fd = arg_int(arg_n);
	struct file *f = fd_get(thiscpu()->proc->fd_table, fd);
	if (!f)
		return -EBADF;
	*fp = f;
	return 0;
}

void fdput(struct file *fp)
{
	if (fp)
		file_put(fp);
}

int fdnum(int arg_n, int *fdp)
{
	int fd = arg_int(arg_n);
	if (fd < 0)
		return -EBADF;
	*fdp = fd;
	return 0;
}

