static int64_t sys_uname(void)
{
	uintptr_t uaddr = arg_ptr(0);
	struct utsname uts;
	memset(&uts, 0, sizeof(uts));
	strncpy(uts.sysname, "Linux", sizeof(uts.sysname) - 1);
	strncpy(uts.nodename, "noobkernel", sizeof(uts.nodename) - 1);
	strncpy(uts.release, "5.10.0", sizeof(uts.release) - 1);
	strncpy(uts.version, "#1 SMP", sizeof(uts.version) - 1);
	strncpy(uts.machine, "riscv64", sizeof(uts.machine) - 1);
	if (uaddr < USER_BASE || uaddr + sizeof(uts) > USER_TOP)
		return -EFAULT;
	return copyout(thiscpu()->proc->pagetable, uaddr, &uts, sizeof(uts))
		   ? -EFAULT : 0;
}

/* ── stub implementations (return -ENOSYS until implemented) ── */

static int64_t stub_enosys(void)  { return -ENOSYS; }
static int64_t stub_ok(void)      { return 0; }

void syscall_dispatch(void)
{
	struct proc *p = thiscpu()->proc;
	struct trapframe *tf = p->tf;
	int64_t nr = tf->a7;
	if (nr >= NR_SYSCALLS || nr < 0) {
		tf->a0 = -ENOSYS;
		tf->epc += 4;
		return;
	}

	int64_t ret = -ENOSYS;

	switch (nr) {
	/* file I/O */
	case SYS_write:    ret = sys_write();   break;
	case SYS_read:     ret = sys_read();    break;
	case SYS_writev:   ret = sys_writev();  break;
	case SYS_readv:    ret = sys_readv();   break;
	case SYS_openat:   ret = sys_openat();         break;
	case SYS_close:    ret = sys_close();   break;
	case SYS_pipe2:    ret = sys_pipe2();   break;
	case SYS_dup:      ret = sys_dup();      break;
	case SYS_dup3:     ret = sys_dup2();     break;

	/* directory */
	case SYS_getdents64: ret = sys_getdents64(); 	break;
	case SYS_getcwd:     ret = sys_getcwd(); 		break;
	case SYS_chdir:      ret = sys_chdir(); 		break;
	case SYS_mkdirat:    ret = sys_mkdirat();     		break;
	case SYS_unlinkat:   ret = sys_unlinkat();    		break;
	case SYS_linkat:     ret = stub_enosys(); 		break;
	case SYS_umount2:    ret = sys_umount2();     		break;
	case SYS_mount:      ret = sys_mount();       		break;
	case SYS_fstat:      ret = sys_fstat(); 		break;

	/* process control */
	case SYS_exit:
		sys_exit();
		return;
	case SYS_getpid:   ret = sys_getpid();  break;
	case SYS_getppid:  ret = sys_getppid();  break;
	case SYS_clone:    ret = sys_clone();   break;
	case SYS_execve:
		ret = sys_execve();
		if (ret >= 0) { tf->a0 = 0; return; }
		break;
	case SYS_wait4:    ret = sys_wait4();   break;
	case SYS_kill:     ret = sys_kill();    break;

	/* signal */
	case SYS_rt_sigaction: ret = sys_rt_sigaction(); break;
	case SYS_rt_sigreturn: ret = sys_rt_sigreturn(); break;

	/* memory */
	case SYS_brk:      ret = sys_brk();    	break;
	case SYS_mmap:     ret = sys_mmap();       break;
	case SYS_mprotect: ret = stub_ok();     break;
	case SYS_madvise:  ret = stub_ok();     break;
	case SYS_munmap:   ret = sys_munmap();         break;

	/* timer */
	case SYS_nanosleep:    ret = sys_nanosleep();    break;
	case SYS_gettimeofday: ret = sys_gettimeofday(); break;
	case SYS_times:        ret = sys_times();       break;

	/* misc */
	case SYS_sched_yield:
		sched_yield();
		tf->a0 = 0;
		tf->epc += 4;
		return;
	case SYS_uname:        ret = sys_uname(); break;

	/* custom */
	case SYS_shutdown:
		sys_shutdown();
		return;

	case SYS_set_tid_address: ret = stub_ok(); break;
	case SYS_set_robust_list: ret = stub_ok(); break;
	case SYS_rt_sigprocmask: ret = stub_ok(); break;
	case SYS_rt_sigsuspend: ret = stub_ok(); break;
	case SYS_getuid:  ret = 0; break;
	case SYS_geteuid: ret = 0; break;
	case SYS_getgid:  ret = 0; break;
	case SYS_getegid: ret = 0; break;
	case SYS_setpgid: ret = 0; break;
	case SYS_setsid:  ret = 0; break;
	case SYS_umask:   ret = 0; break;
	case SYS_clock_gettime: ret = stub_ok(); break;
	default:
		ret = -ENOSYS;
		break;
	}

	tf->a0 = ret;
	tf->epc += 4;
}

