/* 文件系统相关系统调用：sys_write / sys_read / sys_open / sys_close
 *
 * sys_write:  写数据到 fd
 *   fd=1/2（stdout/stderr）→ 直接写 UART
 *   其他 fd → fdget 查表，走 VFS 层（管道、文件等）
 *
 * sys_read:   从 fd 读取数据
 *   fd=0（stdin）→ 从 UART 环形缓冲区读取
 *     空缓冲区时 sleep 等待，有信号时返回 -EINTR
 *   其他 fd → fdget 查表，走 VFS 层
 *
 * sys_open:   打开文件
 *   fetch_str 取得路径并校验用户空间地址合法性
 *   成功后分配 fd，安装到进程的 fd_table
 *
 * sys_close:  关闭文件描述符
 *   fdnum 仅提取 fd 号做基本校验，再手动 fd_free + vfs_close
 */
#include <syscall/syscall.h>
#include <hal/uart.h>
#include <task/proc.h>
#include <task/sched.h>
#include <mm/kalloc.h>
#include <fs/vfs.h>
#include <fs/fd_table.h>
#include <fs/file.h>
#include <sync/spinlock.h>
#include <misc/errno.h>
#include <misc/string.h>
#include <ipc/signal.h>

int64_t sys_write(void)
{
	uintptr_t buf = arg_ptr(1);
	size_t len = arg_size(2);

	struct file *f;
	if (fdget(0, &f) < 0)
		return -EBADF;

	char *kbuf = kzalloc(len < 4096 ? len : 4096);
	if (!kbuf) {
		fdput(f);
		return -ENOMEM;
	}

	size_t written = 0;
	while (written < len) {
		size_t chunk = len - written;
		if (chunk > 4096)
			chunk = 4096;
		if (copyin(thiscpu()->proc->pagetable,
			   kbuf, buf + written, chunk)) {
			kfree(kbuf);
			fdput(f);
			return -EFAULT;
		}
		ssize_t ret = vfs_write(f, kbuf, chunk);
		if (ret < 0) {
			kfree(kbuf);
			fdput(f);
			return ret;
		}
		written += ret;
		if ((size_t)ret < chunk)
			break;
	}
	kfree(kbuf);
	fdput(f);
	return written;
}

int64_t sys_read(void)
{
	uintptr_t buf = arg_ptr(1);
	size_t len = arg_size(2);

	struct file *f;
	if (fdget(0, &f) < 0)
		return -EBADF;

	char *kbuf = kzalloc(len < 4096 ? len : 4096);
	if (!kbuf) {
		fdput(f);
		return -ENOMEM;
	}

	ssize_t ret = vfs_read(f, kbuf, len);
	if (ret > 0) {
		if (copyout(thiscpu()->proc->pagetable, buf, kbuf, ret)) {
			kfree(kbuf);
			fdput(f);
			return -EFAULT;
		}
	}
	kfree(kbuf);
	fdput(f);
	return ret;
}

int64_t sys_openat(void)
{
	char path[256];
	int ret = fetch_str(path, 1, sizeof(path));
	if (ret < 0)
		return ret;
	u32 flags = arg_uint(2);

	struct file *f = vfs_open(path, flags);
	if (!f || (unsigned long)f >= (unsigned long)-MAX_ERRNO || !f->f_op)
		return -ENOENT;

	int fd = fd_alloc(thiscpu()->proc->fd_table);
	if (fd < 0) {
		vfs_close(f);
		return -EMFILE;
	}
	fd_install(thiscpu()->proc->fd_table, fd, f);
	return fd;
}

int64_t sys_close(void)
{
	int fd;
	if (fdnum(0, &fd) < 0)
		return -EBADF;

	struct proc *p = thiscpu()->proc;
	struct file *f = fd_get(p->fd_table, fd);
	if (!f)
		return -EBADF;
	fd_free(p->fd_table, fd);
	vfs_close(f);
	return 0;
}

int64_t sys_fstat(void)
{
	struct file *f;
	if (fdget(0, &f) < 0)
		return -EBADF;

	if (!f->f_inode) {
		fdput(f);
		return -EINVAL;
	}

	struct kstat ks;
	memset(&ks, 0, sizeof(ks));
	ks.st_dev = 0;
	ks.st_ino = f->f_inode->i_ino;
	ks.st_mode = f->f_inode->i_mode;
	ks.st_nlink = f->f_inode->i_nlink;
	ks.st_uid = f->f_inode->i_uid;
	ks.st_gid = f->f_inode->i_gid;
	ks.st_rdev = f->f_inode->i_rdev;
	ks.st_size = f->f_inode->i_size;
	ks.st_blksize = 4096;
	ks.st_blocks = f->f_inode->i_blocks;
	ks.st_atime_sec = f->f_inode->i_atime;
	ks.st_mtime_sec = f->f_inode->i_mtime;
	ks.st_ctime_sec = f->f_inode->i_ctime;

	fdput(f);
	return store_data(1, &ks, sizeof(ks)) ? -EFAULT : 0;
}
int64_t sys_getdents64(void)
{
	struct file *f;
	if (fdget(0, &f) < 0)
		return -EBADF;

	if (!f->f_op || !f->f_op->readdir) {
		fdput(f);
		return -ENOTDIR;
	}

	uintptr_t ubuf = arg_ptr(1);
	size_t len = arg_size(2);

	void *kbuf = kzalloc(len);
	if (!kbuf) {
		fdput(f);
		return -ENOMEM;
	}

	ssize_t ret = f->f_op->readdir(f, kbuf, len, &f->f_pos);
	if (ret > 0) {
		if (copyout(thiscpu()->proc->pagetable, ubuf, kbuf, ret)) {
			kfree(kbuf);
			fdput(f);
			return -EFAULT;
		}
	}
	kfree(kbuf);
	fdput(f);
	return ret;
}

int64_t sys_writev(void)
{
	uintptr_t iov_va = arg_ptr(1);
	int iovcnt = arg_int(2);

	size_t total = 0;
	for (int i = 0; i < iovcnt && i < 256; i++) {
		u64 iov[2];
		if (copyin(thiscpu()->proc->pagetable, iov, iov_va + i * 16, 16))
			return -EFAULT;
		uintptr_t buf = iov[0];
		size_t len = iov[1];
		if (len == 0) continue;

		struct file *f;
		if (fdget(0, &f) < 0) return -EBADF;
		char *kbuf = kzalloc(len < 4096 ? len : 4096);
		if (!kbuf) { fdput(f); return -ENOMEM; }
		if (copyin(thiscpu()->proc->pagetable, kbuf, buf, len)) {
			kfree(kbuf); fdput(f); return -EFAULT;
		}
		ssize_t ret = vfs_write(f, kbuf, len);
		kfree(kbuf); fdput(f);
		if (ret < 0) return ret;
		total += ret;
	}
	return total;
}

int64_t sys_readv(void)
{
	uintptr_t iov_va = arg_ptr(1);
	int iovcnt = arg_int(2);

	size_t total = 0;
	for (int i = 0; i < iovcnt && i < 32; i++) {
		u64 iov[2];
		if (copyin(thiscpu()->proc->pagetable, iov, iov_va + i * 16, 16))
			return -EFAULT;
		uintptr_t buf = iov[0];
		size_t len = iov[1];
		if (len == 0) continue;

		struct file *f;
			if (fdget(0, &f) < 0) return -EBADF;
			char kbuf[4096];
			size_t chunk = len < 4096 ? len : 4096;
			ssize_t ret = vfs_read(f, kbuf, chunk);
			if (ret > 0) {
		if (copyout(thiscpu()->proc->pagetable, buf, kbuf, ret)) {
		fdput(f); return -EFAULT;
		}
				total += ret;
			}
			fdput(f);
			if (ret < 0) return ret;
	}
	return total;
}

int64_t sys_dup(void)
{
	struct proc *p = thiscpu()->proc;
	int oldfd = arg_int(0);
	struct file *f = fd_get(p->fd_table, oldfd);
	if (!f)
		return -EBADF;
	int newfd = fd_alloc(p->fd_table);
	if (newfd < 0)
		return -EMFILE;
	file_get(f);
	fd_install(p->fd_table, newfd, f);
	return newfd;
}

int64_t sys_dup2(void)
{
	struct proc *p = thiscpu()->proc;
	struct fd_table *fdt = p->fd_table;
	int oldfd = arg_int(0);
	int newfd = arg_int(1);
	/* flags = arg_int(2);  clamped by dup3 semantics, ignored for now */

	if (newfd < 0 || newfd >= (int)NR_OPEN_MAX)
		return -EBADF;

	if (oldfd == newfd) {
		/* validate oldfd is open */
		struct file *f = fd_get(fdt, oldfd);
		if (!f)
			return -EBADF;
		file_put(f);
		return newfd;
	}

	struct file *old = fd_get(fdt, oldfd);
	if (!old)
		return -EBADF;

	/* expand fd_table if needed to accommodate newfd */
	spinlock_acquire(&fdt->lock);
	if ((u32)newfd >= fdt->max_fds) {
		u32 new_max = fdt->max_fds;
		while (new_max <= (u32)newfd && new_max < NR_OPEN_MAX)
			new_max *= 2;
		if (new_max > NR_OPEN_MAX)
			new_max = NR_OPEN_MAX;

		struct file **new_fds =
		    kmalloc(sizeof(struct file *) * new_max);
		if (!new_fds) {
			spinlock_release(&fdt->lock);
			file_put(old);
			return -ENOMEM;
		}
		for (u32 i = 0; i < fdt->max_fds; i++)
			new_fds[i] = fdt->fds[i];
		for (u32 i = fdt->max_fds; i < new_max; i++)
			new_fds[i] = NULL;
		kfree(fdt->fds);
		fdt->fds = new_fds;
		fdt->max_fds = new_max;
	}
	spinlock_release(&fdt->lock);

	/* close newfd if already open (dup2 semantics) */
	struct file *exist = fd_get(fdt, newfd);
	if (exist) {
		fd_free(fdt, newfd);
		file_put(exist); /* drop lookup ref */
		file_put(exist); /* drop table ref */
	}

	file_get(old); /* extra ref for newfd */
	fd_install(fdt, newfd, old);
	file_put(old); /* drop lookup ref */
	return newfd;
}

int64_t sys_mkdirat(void)
{
	char path[256];
	if (fetch_str(path, 0, sizeof(path)) < 0)
		return -EFAULT;
	umode_t mode = arg_uint(1);
	return vfs_mkdir(path, mode);
}

int64_t sys_unlinkat(void)
{
	char path[256];
	if (fetch_str(path, 1, sizeof(path)) < 0) {
		printf("unlinkat: fetch_str FAIL\n");
		return -EFAULT;
	}
	printf("unlinkat: dirfd=%d path='%s'\n", arg_int(0), path);
	int ret = vfs_unlink(path);
	printf("unlinkat: ret=%d\n", ret);
	return ret;
}

