/* 进程间通信相关系统调用：sys_pipe / sys_kill / sys_sigaction / sys_sigreturn
 *
 * sys_pipe: 创建管道
 *   分配 pipe 结构 + 两个 file 对象（读端/写端）
 *   读端挂 pipe_read_fops（.read = pipe_read）, 写端挂 pipe_write_fops
 *   文件描述符通过 store_data 写回用户空间的 int[2]
 *   关键：先 fd_install 读端再 fd_alloc 写端，避免两调用返回同一 fd
 *
 * sys_kill: 向指定进程发送信号
 *   遍历 proc_list 找到目标进程
 *   设置 sig_pending 位，若进程在睡眠则强制唤醒（设为 RUNNABLE + 入队）
 *
 * sys_sigaction: 注册信号处理函数
 *   保存原有 handler 指针，设置新 handler
 *   SIGKILL 不可被捕获，返回 -EINVAL
 *
 * sys_sigreturn: 从信号处理函数返回
 *   恢复保存的 saved_tf 到 trapframe，清除 in_signal_handler 标志
 */
#include <syscall/syscall.h>
#include <task/proc.h>
#include <task/sched.h>
#include <mm/kalloc.h>
#include <misc/string.h>
#include <misc/errno.h>
#include <fs/vfs.h>
#include <fs/fd_table.h>
#include <fs/file.h>
#include <sync/spinlock.h>
#include <ipc/pipe.h>
#include <ipc/signal.h>

int64_t sys_pipe2(void)
{
	struct proc *p = thiscpu()->proc;

	struct pipe *pi = pipe_alloc();
	if (!pi)
		return -ENOMEM;

	struct file *rf = file_alloc();
	struct file *wf = file_alloc();
	if (!rf || !wf) {
		if (rf)
			file_put(rf);
		if (wf)
			file_put(wf);
		kfree(pi);
		return -ENOMEM;
	}

	static struct file_operations pipe_read_fops = {
		.read = pipe_read,
		.release = pipe_release,
	};
	static struct file_operations pipe_write_fops = {
		.write = pipe_write,
		.release = pipe_release,
	};

	rf->f_op = &pipe_read_fops;
	rf->f_private = pi;
	rf->f_mode = O_RDONLY;
	wf->f_op = &pipe_write_fops;
	wf->f_private = pi;
	wf->f_mode = O_WRONLY;

	pi->nreaders = 1;
	pi->nwriters = 1;
	pi->nref = 2;

	int rfd = fd_alloc(p->fd_table);
	if (rfd < 0) {
		file_put(rf);
		file_put(wf);
		kfree(pi);
		return -EMFILE;
	}
	fd_install(p->fd_table, rfd, rf);

	int wfd = fd_alloc(p->fd_table);
	if (wfd < 0) {
		fd_free(p->fd_table, rfd);
		file_put(wf);
		kfree(pi);
		return -EMFILE;
	}
	fd_install(p->fd_table, wfd, wf);

	int fds[2] = { rfd, wfd };
	int ret = store_data(0, fds, sizeof(fds));
	if (ret < 0) {
		fd_free(p->fd_table, rfd);
		fd_free(p->fd_table, wfd);
	}
	return ret;
}

int64_t sys_kill(void)
{
	int pid = arg_pid(0);
	int sig = arg_int(1);

	if (sig < 0 || sig >= NSIG)
		return -EINVAL;

	spinlock_acquire(&proc_list_lock);
	struct proc *target;
	list_for_each_entry(target, &proc_list, proc_list)
	{
		if (target->pid == pid) {
			target->sig_pending |= (1ULL << sig);
			spinlock_acquire(&target->lock);
			if (target->state == PROC_SLEEPING) {
				target->state = PROC_RUNNABLE;
				enqueue_proc(r_tp(), target);
			}
			spinlock_release(&target->lock);
			spinlock_release(&proc_list_lock);
			return 0;
		}
	}
	spinlock_release(&proc_list_lock);
	return -ESRCH;
}

int64_t sys_rt_sigaction(void)
{
	int sig = arg_int(0);
	uintptr_t handler_va = arg_ptr(1);

	if (sig < 0 || sig >= NSIG)
		return -EINVAL;
	if (sig == SIGKILL)
		return -EINVAL;

	struct proc *p = thiscpu()->proc;
	void (*old)(int) = p->sighandlers[sig];
	p->sighandlers[sig] = (void (*)(int))handler_va;
	return (int64_t)(uintptr_t)old;
}

int64_t sys_rt_sigreturn(void)
{
	struct proc *p = thiscpu()->proc;
	memcpy(p->tf, &p->saved_tf, sizeof(struct trapframe));
	p->in_signal_handler = false;
	return p->tf->a0;
}

#include <syscall/syscall.h>
#include <task/proc.h>
#include <task/sched.h>
#include <mm/kalloc.h>
#include <mm/pagetable.h>
#include <mm/vm.h>
#include <mm/vma.h>
#include <misc/string.h>
#include <misc/errno.h>
#include <misc/align.h>
#include <misc/log.h>
#include <fs/file.h>
#include <fs/vfs.h>
#include <fs/fd_table.h>

#define MAP_SHARED       0x01
#define MAP_PRIVATE      0x02
#define MAP_FIXED        0x10
#define MAP_ANONYMOUS    0x20

static int prot_to_pte(int prot)
{
	int pte = PTE_V | PTE_U;
	if (prot & 0x1) pte |= PTE_R;
	if (prot & 0x2) pte |= PTE_W;
	if (prot & 0x4) pte |= PTE_X;
	return pte;
}

static uintptr_t mmap_next = 0x10000000;

static uintptr_t __attribute__((noinline))
find_free_addr(struct proc *p, size_t size)
{
	uintptr_t va = mmap_next;
	mmap_next += PAGE_ALIGN_UP(size);
	if (mmap_next > USER_TOP)
		mmap_next = 0x10000000;
	return va;
}

int64_t sys_mmap(void)
{
	struct proc *p = thiscpu()->proc;
	uintptr_t addr = arg_ptr(0);
	size_t length = arg_size(1);
	int prot = arg_int(2);
	int flags = arg_int(3);
	int fd_val = arg_int(4);
	off_t offset = (off_t)arg_raw(5);

	if (length == 0) {
		return -EINVAL;
	}

	size_t npages = (length + PAGE_SIZE - 1) / PAGE_SIZE;
	int pte_perm = prot_to_pte(prot);
	uintptr_t va;
	struct file *file = NULL;

	if (!(flags & MAP_ANONYMOUS)) {
		if (fdnum(4, &fd_val) < 0)
			return -EBADF;
		file = fd_get(p->fd_table, fd_val);
		if (!file)
			return -EBADF;
	}

	if (addr)
		va = PAGE_ALIGN_DOWN(addr);
	else
		va = find_free_addr(p, npages * PAGE_SIZE);

	if (!va || va + npages * PAGE_SIZE > USER_TOP) {
		if (file) fdput(file);
		return -ENOMEM;
	}

	if (flags & MAP_FIXED) {
		unmappages(p->pagetable, va, npages);
		vma_remove(p, va, npages * PAGE_SIZE);
	} else {
		pte_t *pte = va2pte(p->pagetable, va, false);
		if (pte && (*pte & PTE_M)) {
			if (file) fdput(file);
			return -EADDRINUSE;
		}
	}

	loff_t saved_off = file ? file->f_pos : 0;

	for (size_t i = 0; i < npages; i++) {
		void *page = kzalloc_page();
		if (!page) {
			if (file) { file->f_pos = saved_off; fdput(file); }
			return -ENOMEM;
		}
		uintptr_t page_va = va + i * PAGE_SIZE;

		if (file) {
			loff_t read_off = offset + (loff_t)i * PAGE_SIZE;
			vfs_lseek(file, read_off, SEEK_SET);
			ssize_t nr = vfs_read(file, page, PAGE_SIZE);
			if (nr < 0)
				memset(page, 0, PAGE_SIZE);
		}

		if (mappages(p->pagetable, page_va, (uintptr_t)page, 1,
			     pte_perm | PTE_M)) {
			kfree_page(page);
			if (file) { file->f_pos = saved_off; fdput(file); }
			return -ENOMEM;
		}
	}

	if (file)
		file->f_pos = saved_off;
	return va;
}

int64_t sys_munmap(void)
{
	struct proc *p = thiscpu()->proc;
	uintptr_t start = arg_ptr(0);
	size_t length = arg_size(1);

	if (!PAGE_ALIGNED(start) || length == 0)
		return -EINVAL;

	size_t npages = (length + PAGE_SIZE - 1) / PAGE_SIZE;
	unmappages(p->pagetable, start, npages);
	vma_remove(p, start, npages * PAGE_SIZE);
	return 0;
}

/* 用户空间内存访问工具：copyin / copyout / copyinstr / fetch_* / store_*
 *
 * 在用户页表的虚拟地址和内核缓冲区之间安全地拷贝数据
 * 使用 walkaddr 逐页翻译虚拟地址，处理跨页边界的情况
 * 出错时返回 -EFAULT（无效地址），不回滚已拷贝的部分
 *
 * copyin:   从用户空间拷贝数据到内核
 * copyout:  从内核拷贝数据到用户空间
 * copyinstr:从用户空间拷贝以 '\0' 结尾的字符串到内核
 *           至多拷贝 max 字节，超长返回 -ENAMETOOLONG
 *
 * fetch_data: 从 trapframe arg_n 取用户指针 → 校验 → copyin
 * fetch_str:  从 trapframe arg_n 取用户字符串指针 → 校验 → copyinstr
 * store_data: 从 trapframe arg_n 取用户指针 → 校验 → copyout
 */
#include <syscall/syscall.h>
#include <mm/pagetable.h>
#include <mm/vm.h>
#include <misc/string.h>
#include <misc/errno.h>

static inline int user_range_ok(uintptr_t uaddr, size_t len)
{
	if (uaddr < USER_BASE)
		return 0;
	if (uaddr >= USER_TOP)
		return 0;
	if (uaddr + len < uaddr)
		return 0;
	if (uaddr + len > USER_TOP)
		return 0;
	return 1;
}

int fetch_data(void *dst, int arg_n, size_t len)
{
	uintptr_t uaddr = arg_ptr(arg_n);
	if (!user_range_ok(uaddr, len))
		return -EFAULT;
	return copyin(thiscpu()->proc->pagetable, dst, uaddr, len);
}

int fetch_str(char *dst, int arg_n, size_t max)
{
	uintptr_t uaddr = arg_ptr(arg_n);
	if (!user_range_ok(uaddr, 1))
		return -EFAULT;
	return copyinstr(thiscpu()->proc->pagetable, dst, uaddr, max);
}

int store_data(int arg_n, const void *src, size_t len)
{
	uintptr_t uaddr = arg_ptr(arg_n);
	if (!user_range_ok(uaddr, len))
		return -EFAULT;
	return copyout(thiscpu()->proc->pagetable, uaddr, src, len);
}

int copyin(pagetable_t pagetable, void *dst, uintptr_t srcva, size_t len)
{
	while (len > 0) {
		uintptr_t pa = walkaddr(pagetable, srcva);
		if (pa == 0) {
			return -EFAULT;
		}
		size_t off = srcva & (PAGE_SIZE - 1);
		size_t n = PAGE_SIZE - off;
		if (n > len)
			n = len;
		memcpy(dst, (const void *)(pa + off), n);
		dst += n;
		srcva += n;
		len -= n;
	}
	return 0;
}

int copyout(pagetable_t pagetable, uintptr_t dstva, const void *src,
	    size_t len)
{
	while (len > 0) {
		uintptr_t pa = walkaddr(pagetable, dstva);
		if (pa == 0)
			return -EFAULT;
		size_t off = dstva & (PAGE_SIZE - 1);
		size_t n = PAGE_SIZE - off;
		if (n > len)
			n = len;
		memcpy((void *)(pa + off), src, n);
		src += n;
		dstva += n;
		len -= n;
	}
	return 0;
}

int copyinstr(pagetable_t pagetable, char *dst, uintptr_t srcva, size_t max)
{
	size_t copied = 0;
	while (copied < max) {
		uintptr_t pa = walkaddr(pagetable, srcva);
		if (pa == 0)
			return -EFAULT;
		size_t off = srcva & (PAGE_SIZE - 1);
		while (off < PAGE_SIZE && copied < max) {
			char c = *(char *)(pa + off);
			dst[copied] = c;
			copied++;
			off++;
			srcva++;
			if (c == 0)
				return 0;
		}
	}
	dst[max - 1] = 0;
	return -ENAMETOOLONG;
}

#include <fs/vfs.h>
#include <misc/log.h>
#include <misc/string.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <mm/kalloc.h>
#include <sync/spinlock.h>

static struct {
	struct list_head fs_list;
	struct list_head mount_list;
	struct list_head super_list;
	spinlock_t lock;
	struct mount *root_mount;
} vfs_state;

void vfs_init(void)
{
	INIT_LIST_HEAD(&vfs_state.fs_list);
	INIT_LIST_HEAD(&vfs_state.mount_list);
	INIT_LIST_HEAD(&vfs_state.super_list);
	vfs_state.lock = SPINLOCK_INITIALIZER("vfs");
	vfs_state.root_mount = NULL;

	super_init();
	inode_init();
	dentry_init();
	file_init();

	infof("vfs initialized");
}

int register_filesystem(struct file_system_type *fs)
{
	if (!fs || !fs->name || !fs->mount) {
		return -EINVAL;
	}

	spinlock_acquire(&vfs_state.lock);

	struct file_system_type *existing;
	list_for_each_entry(existing, &vfs_state.fs_list, fs_list)
	{
		if (strcmp(existing->name, fs->name) == 0) {
			spinlock_release(&vfs_state.lock);
			return -EEXIST;
		}
	}

	INIT_LIST_HEAD(&fs->fs_list);
	fs->fs_lock = SPINLOCK_INITIALIZER(fs->name);
	list_add(&fs->fs_list, &vfs_state.fs_list);

	spinlock_release(&vfs_state.lock);

	infof("filesystem '%s' registered", fs->name);
	return 0;
}

int unregister_filesystem(struct file_system_type *fs)
{
	if (!fs) {
		return -EINVAL;
	}

	spinlock_acquire(&vfs_state.lock);

	bool found = false;
	struct file_system_type *existing;
	list_for_each_entry(existing, &vfs_state.fs_list, fs_list)
	{
		if (existing == fs) {
			found = true;
			break;
		}
	}

	if (!found) {
		spinlock_release(&vfs_state.lock);
		return -ENOENT;
	}

	list_del(&fs->fs_list);
	spinlock_release(&vfs_state.lock);

	infof("filesystem '%s' unregistered", fs->name);
	return 0;
}

struct file_system_type *get_fs(const char *name)
{
	if (!name) {
		return NULL;
	}

	spinlock_acquire(&vfs_state.lock);

	struct file_system_type *fs;
	list_for_each_entry(fs, &vfs_state.fs_list, fs_list)
	{
		if (strcmp(fs->name, name) == 0) {
			spinlock_release(&vfs_state.lock);
			return fs;
		}
	}

	spinlock_release(&vfs_state.lock);
	return NULL;
}

struct super_block *vfs_mount(struct file_system_type *fs_type, dev_t dev,
			      void *data)
{
	if (!fs_type) {
		return PTR(-EINVAL);
	}

	struct super_block *sb = fs_type->mount(fs_type, dev, data);
	if (IS_ERR(sb)) {
		return sb;
	}

	spinlock_acquire(&vfs_state.lock);
	list_add(&sb->s_list, &vfs_state.super_list);
	spinlock_release(&vfs_state.lock);

	infof("mounted filesystem '%s' on device %d:%d", fs_type->name,
	      MAJOR(dev), MINOR(dev));
	return sb;
}

int vfs_umount(struct super_block *sb)
{
	if (!sb) {
		return -EINVAL;
	}

	spinlock_acquire(&vfs_state.lock);
	list_del(&sb->s_list);
	spinlock_release(&vfs_state.lock);

	if (sb->s_type && sb->s_type->kill_sb) {
		sb->s_type->kill_sb(sb);
	}

	infof("unmounted filesystem");
	return 0;
}

int vfs_mount_root(struct file_system_type *fs_type, dev_t dev)
{
	struct super_block *sb = vfs_mount(fs_type, dev, NULL);
	if (IS_ERR(sb)) {
		return PTR_ERR(sb);
	}

	struct mount *mnt = kmalloc(sizeof(struct mount));
	if (!mnt) {
		vfs_umount(sb);
		return -ENOMEM;
	}

	mnt->mnt_parent = NULL;
	mnt->mnt_mountpoint = sb->s_root;
	mnt->mnt_root = sb->s_root;
	mnt->mnt_sb = sb;
	INIT_LIST_HEAD(&mnt->mnt_mounts);
	INIT_LIST_HEAD(&mnt->mnt_child);
	mnt->mnt_lock = SPINLOCK_INITIALIZER("mount");
	mnt->mnt_flags = 0;

	spinlock_acquire(&vfs_state.lock);
	vfs_state.root_mount = mnt;
	list_add(&mnt->mnt_child, &vfs_state.mount_list);
	spinlock_release(&vfs_state.lock);

	infof("root filesystem mounted");
	return 0;
}

struct dentry *vfs_get_root(void)
{
	spinlock_acquire(&vfs_state.lock);
	struct dentry *root =
	    vfs_state.root_mount ? vfs_state.root_mount->mnt_root : NULL;
	spinlock_release(&vfs_state.lock);
	return root;
}

struct mount *vfs_get_root_mount(void)
{
	spinlock_acquire(&vfs_state.lock);
	struct mount *mnt = vfs_state.root_mount;
	spinlock_release(&vfs_state.lock);
	return mnt;
}

struct mount *vfs_lookup_mount(struct dentry *mountpoint)
{
	if (!mountpoint) {
		return NULL;
	}

	spinlock_acquire(&vfs_state.lock);

	struct mount *mnt;
	list_for_each_entry(mnt, &vfs_state.mount_list, mnt_child)
	{
		if (mnt->mnt_mountpoint == mountpoint) {
			spinlock_release(&vfs_state.lock);
			return mnt;
		}
	}

	spinlock_release(&vfs_state.lock);
	return NULL;
}

void vfs_mount_get(struct mount *mnt)
{
	if (!mnt) {
		return;
	}

	spinlock_acquire(&mnt->mnt_lock);
	mnt->mnt_refcnt++;
	spinlock_release(&mnt->mnt_lock);
}

void vfs_mount_put(struct mount *mnt)
{
	if (!mnt) {
		return;
	}

