struct ramfs_node {
	char name[256];
	umode_t mode;
	struct ramfs_node *parent;
	struct list_head children;
	struct list_head sibling;
	char *data;
	size_t data_size;
	struct inode *inode;
};

struct ramfs_sb_info {
	struct ramfs_node *root;
	ino_t next_ino;
};

static struct ramfs_node *ramfs_create_node(struct ramfs_node *parent,
					    const char *name, umode_t mode)
{
	struct ramfs_node *node = kzalloc(sizeof(struct ramfs_node));
	if (!node)
		return NULL;

	strncpy(node->name, name, sizeof(node->name) - 1);
	node->mode = mode;
	node->parent = parent;
	INIT_LIST_HEAD(&node->children);
	INIT_LIST_HEAD(&node->sibling);
	return node;
}

static void ramfs_free_node(struct ramfs_node *node)
{
	if (!node)
		return;

	struct list_head *pos, *n;
	list_for_each_safe(pos, n, &node->children)
	{
		struct ramfs_node *child =
		    list_entry(pos, struct ramfs_node, sibling);
		list_del(&child->sibling);
		ramfs_free_node(child);
	}

	if (node->data)
		kfree(node->data);
	if (node->inode)
		inode_put(node->inode);
	kfree(node);
}

static struct ramfs_node *ramfs_find_child(struct ramfs_node *dir,
					   const char *name)
{
	struct list_head *pos;
	list_for_each(pos, &dir->children)
	{
		struct ramfs_node *child =
		    list_entry(pos, struct ramfs_node, sibling);
		if (strcmp(child->name, name) == 0)
			return child;
	}
	return NULL;
}

struct ramfs_file {
	struct ramfs_node *node;
	loff_t pos;
};

static ssize_t ramfs_read(struct file *file, void *buf, size_t count,
			  loff_t *pos)
{
	struct ramfs_file *rf = file->f_private;
	if (!rf)
		return -EINVAL;

	if (*pos >= rf->node->data_size)
		return 0;

	size_t remaining = rf->node->data_size - *pos;
	if (count > remaining)
		count = remaining;

	memcpy(buf, rf->node->data + *pos, count);
	*pos += count;
	return count;
}

static ssize_t ramfs_write(struct file *file, const void *buf, size_t count,
			   loff_t *pos)
{
	struct ramfs_file *rf = file->f_private;
	if (!rf)
		return -EINVAL;

	size_t new_size = *pos + count;
	if (new_size > rf->node->data_size) {
		char *new_data = kmalloc(new_size);
		if (!new_data)
			return -ENOMEM;
		if (rf->node->data && rf->node->data_size > 0)
			memcpy(new_data, rf->node->data, rf->node->data_size);
		memset(new_data + rf->node->data_size, 0,
		       new_size - rf->node->data_size);
		if (rf->node->data)
			kfree(rf->node->data);
		rf->node->data = new_data;
		rf->node->data_size = new_size;
	}

	memcpy(rf->node->data + *pos, buf, count);
	*pos += count;

	if (*pos > rf->node->data_size)
		rf->node->data_size = *pos;

	if (file->f_inode)
		file->f_inode->i_size = rf->node->data_size;

	return count;
}

static loff_t ramfs_llseek(struct file *file, loff_t offset, int whence)
{
	struct ramfs_file *rf = file->f_private;
	if (!rf)
		return -EINVAL;

	loff_t new_pos;
	switch (whence) {
	case SEEK_SET:
		new_pos = offset;
		break;
	case SEEK_CUR:
		new_pos = rf->pos + offset;
		break;
	case SEEK_END:
		new_pos = rf->node->data_size + offset;
		break;
	default:
		return -EINVAL;
	}

	if (new_pos < 0)
		return -EINVAL;

	rf->pos = new_pos;
	return new_pos;
}

static int ramfs_open(struct inode *inode, struct file *file)
{
	struct ramfs_node *node = inode->i_private;
	if (!node)
		return -ENOENT;

	struct ramfs_file *rf = kzalloc(sizeof(struct ramfs_file));
	if (!rf)
		return -ENOMEM;

	rf->node = node;
	rf->pos = 0;
	file->f_private = rf;
	return 0;
}

static int ramfs_release(struct inode *inode, struct file *file)
{
	if (file->f_private) {
		kfree(file->f_private);
		file->f_private = NULL;
	}
	return 0;
}

static struct file_operations ramfs_file_fops = {
    .read = ramfs_read,
    .write = ramfs_write,
    .llseek = ramfs_llseek,
    .open = ramfs_open,
    .release = ramfs_release,
};

static struct dentry *ramfs_lookup(struct inode *dir, struct dentry *dentry)
{
	struct ramfs_node *dir_node = dir->i_private;
	if (!dir_node)
		return NULL;

	struct ramfs_node *child =
	    ramfs_find_child(dir_node, dentry->d_name.name);
	if (!child)
		return NULL;

	if (child->inode) {
		dentry->d_inode = child->inode;
		child->inode->i_refcnt++;
	} else {
		struct super_block *sb = dir->i_sb;
		struct ramfs_sb_info *sbi = sb->s_fs_info;

		struct inode *inode = inode_alloc(sb);
		if (!inode)
			return NULL;

		inode->i_ino = sbi->next_ino++;
		inode->i_mode = child->mode;
		inode->i_sb = sb;
		inode->i_private = child;
		inode->i_size = child->data_size;

		if (S_ISDIR(child->mode)) {
			inode->i_fop = NULL;
		} else {
			inode->i_fop = &ramfs_file_fops;
		}

		child->inode = inode;
		dentry->d_inode = inode;
	}

	dentry_get(dentry);
	return dentry;
}

static int ramfs_create(struct inode *dir, struct dentry *dentry, umode_t mode)
{
	struct ramfs_node *dir_node = dir->i_private;
	if (!dir_node)
		return -ENOENT;

	struct ramfs_node *existing =
	    ramfs_find_child(dir_node, dentry->d_name.name);
	if (existing)
		return -EEXIST;

	struct super_block *sb = dir->i_sb;
	struct ramfs_sb_info *sbi = sb->s_fs_info;

	struct ramfs_node *node =
	    ramfs_create_node(dir_node, dentry->d_name.name, S_IFREG | mode);
	if (!node)
		return -ENOMEM;
	list_add_tail(&node->sibling, &dir_node->children);

	struct inode *inode = inode_alloc(sb);
	if (!inode) {
		ramfs_free_node(node);
		return -ENOMEM;
	}

	inode->i_ino = sbi->next_ino++;
	inode->i_mode = S_IFREG | mode;
	inode->i_sb = sb;
	inode->i_private = node;
	inode->i_fop = &ramfs_file_fops;
	node->inode = inode;

	dentry->d_inode = inode;
	inode->i_refcnt++;
	return 0;
}

static int ramfs_mkdir(struct inode *dir, struct dentry *dentry, umode_t mode)
{
	struct ramfs_node *dir_node = dir->i_private;
	if (!dir_node)
		return -ENOENT;

	struct ramfs_node *existing =
	    ramfs_find_child(dir_node, dentry->d_name.name);
	if (existing)
		return -EEXIST;

	struct super_block *sb = dir->i_sb;
	struct ramfs_sb_info *sbi = sb->s_fs_info;

	struct ramfs_node *node =
	    ramfs_create_node(dir_node, dentry->d_name.name, S_IFDIR | mode);
	if (!node)
		return -ENOMEM;
	list_add_tail(&node->sibling, &dir_node->children);

	struct inode *inode = inode_alloc(sb);
	if (!inode) {
		ramfs_free_node(node);
		return -ENOMEM;
	}

	inode->i_ino = sbi->next_ino++;
	inode->i_mode = S_IFDIR | mode;
	inode->i_sb = sb;
	inode->i_private = node;
	node->inode = inode;

	dentry->d_inode = inode;
	inode->i_refcnt++;
	return 0;
}

static int ramfs_unlink(struct inode *dir, struct dentry *dentry)
{
	struct ramfs_node *dir_node = dir->i_private;
	if (!dir_node)
		return -ENOENT;

	struct ramfs_node *child =
	    ramfs_find_child(dir_node, dentry->d_name.name);
	if (!child)
		return -ENOENT;

	list_del(&child->sibling);
	if (child->inode) {
		inode_put(child->inode);
		child->inode = NULL;
	}
	dentry->d_inode = NULL;
	ramfs_free_node(child);
	return 0;
}

static int ramfs_rmdir(struct inode *dir, struct dentry *dentry)
{
	struct ramfs_node *dir_node = dir->i_private;
	if (!dir_node)
		return -ENOENT;

	struct ramfs_node *child =
	    ramfs_find_child(dir_node, dentry->d_name.name);
	if (!child)
		return -ENOENT;

	if (!list_empty(&child->children))
		return -ENOTEMPTY;

	list_del(&child->sibling);
	if (child->inode) {
		inode_put(child->inode);
		child->inode = NULL;
	}
	dentry->d_inode = NULL;
	ramfs_free_node(child);
	return 0;
}

static struct inode_operations ramfs_dir_iops = {
    .lookup = ramfs_lookup,
    .create = ramfs_create,
    .mkdir = ramfs_mkdir,
    .unlink = ramfs_unlink,
