static int ext4_readlink(struct inode *inode, char *buf, int bufsize)
{
	struct ext4_inode_info *ei = inode->i_private;
	struct ext4_inode *raw = &ei->raw;

	/* fast symlink: target stored directly in i_block (≤60 bytes) */
	if (inode->i_blocks == 0) {
		int len = inode->i_size < bufsize ? inode->i_size : bufsize;
		memcpy(buf, raw->i_block, len);
		return len;
	}

	/* slow symlink: target stored in data blocks */
	int total = 0;
	loff_t pos = 0;
	if (inode->i_fop && inode->i_fop->read) {
		total = inode->i_fop->read(NULL, buf, bufsize, &pos);
	}
	return total;
}

