static struct super_block *ext4_mount(struct file_system_type *type,
				      dev_t dev, void *data)
{
	struct super_block *sb = super_alloc(type, dev);
	if (!sb)
		return NULL;

	struct ext4_sb_info *sbi = ext4_create_sbi();
	if (!sbi) {
		super_free(sb);
		return NULL;
	}

	infof("ext4: reading superblock...");
	uart_out_flush();
	if (ext4_read_sb(sb, sbi) < 0) {
		errorf("ext4: superblock read failed");
		ext4_free_sbi(sbi);
		super_free(sb);
		return NULL;
	}
	infof("ext4: superblock OK");

	sb->s_op = &ext4_sops;

	struct dentry *root = dentry_root(sb);
	if (!root) {
		ext4_free_sbi(sbi);
		super_free(sb);
		return NULL;
	}

	infof("ext4: reading root inode...");
	uart_out_flush();
	struct ext4_inode raw;
	if (ext4_inode_read(sb, EXT4_ROOT_INO, &raw) < 0) {
		errorf("ext4: root inode read failed");
		ext4_free_sbi(sbi);
		super_free(sb);
		return NULL;
	}

	struct inode *root_inode = inode_alloc(sb);
	if (!root_inode) {
		ext4_free_sbi(sbi);
		super_free(sb);
		return NULL;
	}

	ext4_inode_to_vfs(sb, &raw, root_inode);
	root_inode->i_ino = EXT4_ROOT_INO;
	root_inode->i_op = &ext4_dir_iops;
	root_inode->i_fop = &ext4_dir_fops;
	root_inode->i_state = 0;

	root->d_inode = root_inode;
	sb->s_root = root;

	super_register(sb);

	infof("ext4: mounted successfully");
	return sb;
}

