#include <mm/kalloc.h>
#include <misc/string.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <hal/blk.h>
#include <hal/uart.h>

int ext4_read_sb(struct super_block *sb, struct ext4_sb_info *sbi)
{
	infof("ext4_read_sb: bread sector=%d...",
	      EXT4_SUPERBLOCK_OFFSET / BLOCK_SIZE);
	uart_out_flush();
	struct buf *b = bread(sb->s_dev, EXT4_SUPERBLOCK_OFFSET / BLOCK_SIZE);
	if (!b)
		return -EIO;

	memcpy(&sbi->s_es, b->data,
	       sizeof(sbi->s_es) < BLOCK_SIZE ? sizeof(sbi->s_es) : BLOCK_SIZE);
	brelse(b);

	if (sbi->s_es.s_magic != EXT4_MAGIC) {
		errorf("ext4: bad magic %x", sbi->s_es.s_magic);
		return -EINVAL;
	}

	sbi->s_blocksize_bits = 10 + sbi->s_es.s_log_block_size;
	sbi->s_blocksize = 1U << sbi->s_blocksize_bits;
	sbi->s_inodes_per_group = sbi->s_es.s_inodes_per_group;
	sbi->s_inode_size = sbi->s_es.s_inode_size ? sbi->s_es.s_inode_size : 128;
	sbi->s_blocks_per_group = sbi->s_es.s_blocks_per_group;
	sbi->s_desc_size = sbi->s_es.s_desc_size ? sbi->s_es.s_desc_size
						  : 32;

	sbi->s_blocks_count = sbi->s_es.s_blocks_count_lo |
			     ((u64)sbi->s_es.s_blocks_count_hi << 32);
	sbi->s_groups_count =
	    (sbi->s_blocks_count + sbi->s_blocks_per_group - 1) /
	    sbi->s_blocks_per_group;

	sb->s_blocksize = sbi->s_blocksize;
	sb->s_blocksize_bits = sbi->s_blocksize_bits;
	sb->s_fs_info = sbi;
	sbi->s_dev = sb->s_dev;

	infof("ext4: %u blocks, %u groups, blocksize=%u, inodes/group=%u",
	      (u32)sbi->s_blocks_count, sbi->s_groups_count,
	      sbi->s_blocksize, sbi->s_inodes_per_group);

	return 0;
}

int ext4_read_block(dev_t dev, u32 block_size, u64 block, void *buf)
{
	u32 sectors = block_size / BLOCK_SIZE;
	u64 sector = block * sectors;

	for (u32 i = 0; i < sectors; i++) {
		struct buf *b = bread(dev, sector + i);
		if (!b)
			return -EIO;
		memcpy((u8 *)buf + i * BLOCK_SIZE, b->data, BLOCK_SIZE);
		brelse(b);
	}
	return 0;
}

int ext4_write_block(dev_t dev, u32 block_size, u64 block, const void *buf)
{
	u32 sectors = block_size / BLOCK_SIZE;
	u64 sector = block * sectors;

	for (u32 i = 0; i < sectors; i++) {
		struct buf *b = bread(dev, sector + i);
		if (!b)
			return -EIO;
		memcpy(b->data, (const u8 *)buf + i * BLOCK_SIZE, BLOCK_SIZE);
		bwrite(b);
		brelse(b);
	}
	return 0;
}

int ext4_read_gdesc(struct ext4_sb_info *sbi, u32 group,
		    struct ext4_group_desc *desc)
{
	u64 gdt_block = (EXT4_SUPERBLOCK_OFFSET / sbi->s_blocksize) + 1;
	u32 gdt_off_per_block = sbi->s_blocksize / sbi->s_desc_size;
	u64 block = gdt_block + group / gdt_off_per_block;
	u32 off = (group % gdt_off_per_block) * sbi->s_desc_size;

	void *buf = kzalloc_page();
	if (!buf)
		return -ENOMEM;

	int ret = ext4_read_block(sbi->s_dev, sbi->s_blocksize, block, buf);
	if (ret == 0)
		memcpy(desc, (u8 *)buf + off, sizeof(*desc));

	kfree_page(buf);
	return ret;
}

struct ext4_sb_info *ext4_create_sbi(void)
{
	return kzalloc(sizeof(struct ext4_sb_info));
}

void ext4_free_sbi(struct ext4_sb_info *sbi)
{
	kfree(sbi);
}

/*
 * ext4_inode.c — inode read/write from disk, inode number → block group mapping.
 */
#include <fs/ext4.h>
#include <fs/inode.h>
#include <fs/super.h>
#include <mm/kalloc.h>
#include <misc/string.h>
#include <misc/log.h>
#include <misc/errno.h>

int ext4_inode_read(struct super_block *sb, u32 ino, struct ext4_inode *raw)
{
	struct ext4_sb_info *sbi = sb->s_fs_info;

	if (ino == 0 || ino > sbi->s_inodes_per_group * sbi->s_groups_count)
		return -EINVAL;

	u32 group = (ino - 1) / sbi->s_inodes_per_group;
	u32 idx = (ino - 1) % sbi->s_inodes_per_group;

	struct ext4_group_desc desc;
	int ret = ext4_read_gdesc(sbi, group, &desc);
	if (ret < 0)
		return ret;

	u64 table_lo = desc.bg_inode_table_lo |
		      ((u64)desc.bg_inode_table_hi << 32);
	u64 byte_off = (u64)idx * sbi->s_inode_size;
	u64 block = table_lo + byte_off / sbi->s_blocksize;
	u32 off = byte_off % sbi->s_blocksize;

	void *buf = kzalloc_page();
	if (!buf)
		return -ENOMEM;

	ret = ext4_read_block(sbi->s_dev, sbi->s_blocksize, block, buf);
	if (ret == 0)
		memcpy(raw, (u8 *)buf + off, sbi->s_inode_size < sizeof(*raw) ? sbi->s_inode_size : sizeof(*raw));

	kfree_page(buf);
	return ret;
}

int ext4_inode_write(struct super_block *sb, u32 ino,
		     const struct ext4_inode *raw)
{
	struct ext4_sb_info *sbi = sb->s_fs_info;

	u32 group = (ino - 1) / sbi->s_inodes_per_group;
	u32 idx = (ino - 1) % sbi->s_inodes_per_group;

	struct ext4_group_desc desc;
	int ret = ext4_read_gdesc(sbi, group, &desc);
	if (ret < 0)
		return ret;

	u64 table_lo = desc.bg_inode_table_lo |
		      ((u64)desc.bg_inode_table_hi << 32);
	u64 byte_off = (u64)idx * sbi->s_inode_size;
	u64 block = table_lo + byte_off / sbi->s_blocksize;
	u32 off = byte_off % sbi->s_blocksize;

	void *buf = kzalloc_page();
	if (!buf)
		return -ENOMEM;

	ret = ext4_read_block(sbi->s_dev, sbi->s_blocksize, block, buf);
	if (ret == 0) {
		u32 copy_sz = sbi->s_inode_size < sizeof(*raw) ? sbi->s_inode_size : sizeof(*raw);
		memcpy((u8 *)buf + off, raw, copy_sz);
		ret = ext4_write_block(sbi->s_dev, sbi->s_blocksize, block, buf);
	}

	kfree_page(buf);
	return ret;
}

void ext4_inode_to_vfs(struct super_block *sb, const struct ext4_inode *raw,
		       struct inode *inode)
{
	inode->i_ino = raw->i_osd1;
	inode->i_mode = raw->i_mode;
	inode->i_uid = raw->i_uid;
	inode->i_gid = raw->i_gid;
	inode->i_size = raw->i_size_lo | ((u64)raw->i_size_hi << 32);
	inode->i_blocks = raw->i_blocks_lo;
	inode->i_nlink = raw->i_links_count;
	inode->i_atime = raw->i_atime;
	inode->i_mtime = raw->i_mtime;
	inode->i_ctime = raw->i_ctime;
	inode->i_sb = sb;

	struct ext4_inode_info *ei = kzalloc(sizeof(*ei));
	if (!ei)
		return;
	ei->raw = *raw;
	inode->i_private = ei;
}

void ext4_vfs_to_inode(const struct inode *inode, struct ext4_inode *raw)
{
	raw->i_mode = inode->i_mode;
	raw->i_uid = inode->i_uid;
	raw->i_gid = inode->i_gid;
	raw->i_size_lo = (u32)(inode->i_size & 0xFFFFFFFFULL);
	raw->i_size_hi = (u32)(inode->i_size >> 32);
	raw->i_blocks_lo = (u32)(inode->i_blocks & 0xFFFFFFFFULL);
	raw->i_links_count = inode->i_nlink;
	raw->i_atime = inode->i_atime;
	raw->i_mtime = inode->i_mtime;
	raw->i_ctime = inode->i_ctime;
}

/*
 * ext4_dir.c — directory entry parsing and lookup.
 */
#include <fs/ext4.h>
#include <fs/inode.h>
#include <fs/dentry.h>
#include <fs/super.h>
#include <mm/kalloc.h>
#include <misc/string.h>
#include <misc/errno.h>
#include <fs/file.h>

#define EXT4_FT_UNKNOWN  0
#define EXT4_FT_REG_FILE 1
#define EXT4_FT_DIR      2

int ext4_dir_lookup(struct inode *dir, const struct qstr *name, u32 *out_ino)
{
	struct ext4_sb_info *sbi = dir->i_sb->s_fs_info;
	static u8 dir_buf[4096];
	u8 *block_buf = dir_buf;

	static u8 file_buf[4096];
	u64 pos = 0;
	int found = 0;

	while (pos < dir->i_size) {
		u64 pblock;
		u64 len = sbi->s_blocksize;
		int ret = ext4_file_get_block(dir, pos, &pblock, NULL);
		if (ret < 0)
			break;
		if (len > dir->i_size - pos)
			len = dir->i_size - pos;

		ret = ext4_read_block(sbi->s_dev, sbi->s_blocksize, pblock,
				     block_buf);
		if (ret < 0)
			break;

		memcpy(file_buf, block_buf, len < sizeof(file_buf) ? len : sizeof(file_buf));
		u32 off = 0;
		while (off < len && off < (u32)(dir->i_size - pos)) {
			struct ext4_dir_entry_2 *de =
			    (struct ext4_dir_entry_2 *)(file_buf + off);
			if (de->rec_len == 0)
				break;
			if (de->inode == 0) {
				off += de->rec_len;
				continue;
			}

			// if (de->name_len > 0 && de->name_len < 256) {
			// 	printf("ext4_dir: scan '%.*s' ino=%u rlen=%u\n",
			// 	       de->name_len, de->name, de->inode, de->rec_len);
			// }

			if (de->name_len == name->len &&
			    memcmp(de->name, name->name, name->len) == 0) {
				*out_ino = de->inode;
				found = 1;
				break;
			}
			off += de->rec_len;
		}
		if (found)
			break;
		pos += len;
	}

	return found ? 0 : -ENOENT;
}

static int ext4_dir_add_entry(struct inode *dir, u32 ino, const char *name,
			      int name_len, u8 file_type)
{
	struct ext4_sb_info *sbi = dir->i_sb->s_fs_info;
	void *block_buf = kzalloc_page();
	if (!block_buf)
		return -ENOMEM;

	u64 pos = 0;
	int done = 0;

	while (pos < dir->i_size && !done) {
		u64 pblock;
		ext4_file_get_block(dir, pos, &pblock, NULL);
		ext4_read_block(sbi->s_dev, sbi->s_blocksize, pblock,
			       block_buf);

		u32 off = 0;
		while (off < sbi->s_blocksize) {
			struct ext4_dir_entry_2 *de =
			    (struct ext4_dir_entry_2 *)((u8 *)block_buf + off);
			if (de->rec_len == 0)
				break;
			if (de->inode == 0) {
				off += de->rec_len;
				continue;
			}

			u16 min_len = 8 + de->name_len;
			min_len = (min_len + 3) & ~3;
			if (de->rec_len >= min_len + 8 + name_len) {
				u16 new_rec_len = (8 + name_len + 3) & ~3;
				struct ext4_dir_entry_2 *new_de =
				    (struct ext4_dir_entry_2 *)((u8 *)de +
								min_len);
				new_de->inode = ino;
				new_de->rec_len = de->rec_len - min_len;
				new_de->name_len = name_len;
				new_de->file_type = file_type;
				memcpy(new_de->name, name, name_len);
				de->rec_len = min_len;
				ext4_write_block(sbi->s_dev, sbi->s_blocksize,
						pblock, block_buf);
				done = 1;
				break;
			}
			off += de->rec_len;
		}
		pos += sbi->s_blocksize;
	}

	if (!done) {
		u64 new_block;
		ext4_file_alloc_block(dir, pos, &new_block);
		u32 blk_bytes = sbi->s_blocksize;
		void *new_buf = kzalloc(blk_bytes);
		if (new_buf) {
			struct ext4_dir_entry_2 *de =
			    (struct ext4_dir_entry_2 *)new_buf;
			de->inode = ino;
			de->rec_len = sbi->s_blocksize;
			de->name_len = name_len;
			de->file_type = file_type;
			memcpy(de->name, name, name_len);
			ext4_write_block(sbi->s_dev, sbi->s_blocksize,
					new_block, new_buf);
			dir->i_size += sbi->s_blocksize;
			kfree(new_buf);
			done = 1;
		}
	}

	kfree_page(block_buf);
	return done ? 0 : -ENOSPC;
}

int ext4_dir_create_entry(struct inode *dir, u32 ino,
			  const char *name, int name_len, u32 mode)
{
	u8 type = (mode & EXT2_S_IFMT) == EXT2_S_IFDIR ? EXT4_FT_DIR
						       : EXT4_FT_REG_FILE;
	return ext4_dir_add_entry(dir, ino, name, name_len, type);
}

int ext4_dir_delete_entry(struct inode *dir, const char *name, int name_len)
{
	struct ext4_sb_info *sbi = dir->i_sb->s_fs_info;
	void *block_buf = kzalloc_page();
	if (!block_buf)
		return -ENOMEM;

	u64 pos = 0;
	int found = 0;

	while (pos < dir->i_size && !found) {
		u64 pblock;
		ext4_file_get_block(dir, pos, &pblock, NULL);
		ext4_read_block(sbi->s_dev, sbi->s_blocksize, pblock,
			       block_buf);

		u32 off = 0;
		while (off < sbi->s_blocksize) {
			struct ext4_dir_entry_2 *de =
			    (struct ext4_dir_entry_2 *)((u8 *)block_buf + off);
			if (de->rec_len == 0)
				break;
			if (de->inode == 0) {
				off += de->rec_len;
				continue;
			}

			if (de->name_len == (u8)name_len &&
			    memcmp(de->name, name, name_len) == 0) {
				de->inode = 0;
				ext4_write_block(sbi->s_dev, sbi->s_blocksize,
						pblock, block_buf);
				found = 1;
				break;
			}
			off += de->rec_len;
		}
		pos += sbi->s_blocksize;
	}

	kfree_page(block_buf);
	return found ? 0 : -ENOENT;
}

int ext4_readdir(struct file *file, void *buf, size_t count, loff_t *pos)
{
	struct inode *dir = file->f_inode;
	struct ext4_sb_info *sbi = dir->i_sb->s_fs_info;
	void *block_buf = kzalloc_page();
	if (!block_buf)
		return -ENOMEM;

	size_t total = 0;
	u64 off = *pos;

	while (total + 64 <= count && off < dir->i_size) {
		u64 pblock;
		if (ext4_file_get_block(dir, off, &pblock, NULL) < 0)
			break;

		ext4_read_block(sbi->s_dev, sbi->s_blocksize, pblock,
			       block_buf);

		u32 blk_off = off % sbi->s_blocksize;
		while (blk_off < sbi->s_blocksize && total + 64 <= count) {
			struct ext4_dir_entry_2 *de =
			    (struct ext4_dir_entry_2 *)((u8 *)block_buf +
						       blk_off);
			if (de->rec_len == 0)
				break;
			if (de->inode == 0) {
				blk_off += de->rec_len;
				continue;
			}

			u16 reclen = offsetof(struct linux_dirent64, d_name) +
				     de->name_len + 1;
			reclen = ALIGN_UP(reclen, 8);
			if (total + reclen > count)
				break;

			struct linux_dirent64 *lde =
			    (struct linux_dirent64 *)((u8 *)buf + total);
			lde->d_ino = de->inode;
			lde->d_off = off + blk_off + de->rec_len;
			lde->d_reclen = reclen;
			lde->d_type = de->file_type;
			memcpy(lde->d_name, de->name, de->name_len);
			lde->d_name[de->name_len] = '\0';

			total += reclen;
			blk_off += de->rec_len;
		}
		off = (off & ~((u64)sbi->s_blocksize - 1)) + sbi->s_blocksize;
	}

	*pos = off;
	kfree_page(block_buf);
	return total;
}

/*
 * ext4_file.c — extent tree walking, file block mapping, read/write.
 */
#include <fs/ext4.h>
#include <fs/inode.h>
#include <fs/file.h>
#include <fs/super.h>
#include <mm/kalloc.h>
#include <misc/string.h>
#include <misc/log.h>
#include <misc/errno.h>

static int ext4_block_in_inode(struct ext4_inode *raw, u32 block, u64 *pblock)
{
	if (block < 12) {
		unsigned char *base = (unsigned char *)raw;
		u32 val;
		memcpy(&val, base + 40 + block * 4, sizeof(val));
		*pblock = val;
		return *pblock ? 0 : -ENOENT;
	}
	return -ENOENT;
}

static int ext4_extent_get_block(struct super_block *sb,
				 struct ext4_inode *raw, u32 lblock,
				 u64 *pblock)
{
	struct ext4_sb_info *sbi = sb->s_fs_info;

	struct ext4_extent_header eh;
	memcpy(&eh, raw->i_block, sizeof(eh));
	if (eh.eh_magic != EXT4_EXTENT_MAGIC) {
		return ext4_block_in_inode(raw, lblock, pblock);
	}

	static u8 extent_buf[4096];
	int depth = eh.eh_depth;
	void *cur = raw->i_block; /* start at inode's extent tree root */

	/* walk down the extent tree: depth → 0 */
	while (depth > 0) {
		struct ext4_extent_header *hdr = (struct ext4_extent_header *)cur;
		struct ext4_extent_idx *idx =
		    (struct ext4_extent_idx *)(hdr + 1);
		int found = 0;

		for (int i = 0; i < hdr->eh_entries; i++) {
			/* last entry or lblock falls in this index range */
			if (i + 1 == hdr->eh_entries ||
			    lblock < idx[i + 1].ei_block) {
				u64 next =
				    idx[i].ei_leaf_lo |
				    ((u64)idx[i].ei_leaf_hi << 32);
				if (ext4_read_block(sbi->s_dev,
						    sbi->s_blocksize, next,
						    extent_buf) < 0)
					return -EIO;

				struct ext4_extent_header *nh =
				    (struct ext4_extent_header *)extent_buf;
				if (nh->eh_magic != EXT4_EXTENT_MAGIC ||
				    nh->eh_depth != depth - 1)
					return -ENOENT;

				cur = extent_buf;
				depth--;
				found = 1;
				break;
			}
		}
		if (!found)
			return -ENOENT;
	}

	/* depth == 0: cur points to a leaf block full of extents */
	{
		struct ext4_extent_header *hdr = (struct ext4_extent_header *)cur;
		struct ext4_extent *ex = (struct ext4_extent *)(hdr + 1);

		for (int i = 0; i < hdr->eh_entries; i++) {
			u32 start = ex[i].ee_block;
			u16 len = ex[i].ee_len & 0x7FFF;
			if (lblock >= start && lblock < start + len) {
				*pblock = ((u64)ex[i].ee_start_hi << 32) |
					  ex[i].ee_start_lo;
				*pblock += lblock - start;
				return 0;
			}
		}
	}

	return -ENOENT;
}

int ext4_file_get_block(struct inode *inode, u64 pos, u64 *pblock,
			u64 *max_contig)
{
	struct ext4_inode_info *ei = inode->i_private;
	struct ext4_sb_info *sbi = inode->i_sb->s_fs_info;
	u32 lblock = (u32)(pos / sbi->s_blocksize);

	u64 blk;
	int ret = ext4_extent_get_block(inode->i_sb, &ei->raw, lblock, &blk);
	if (ret < 0)
		return ret;

	*pblock = blk;
	if (max_contig)
		*max_contig = sbi->s_blocksize - (pos % sbi->s_blocksize);
	return 0;
}

int ext4_file_alloc_block(struct inode *inode, u64 pos, u64 *pblock)
{
	struct ext4_inode_info *ei = inode->i_private;
	struct ext4_sb_info *sbi = inode->i_sb->s_fs_info;

	u32 lblock = pos / sbi->s_blocksize;
	if (lblock < 12) {
		u32 val;
		memcpy(&val, &ei->raw.i_block[lblock], sizeof(val));
		if (val == 0) {
			val = lblock + 100;
			memcpy(&ei->raw.i_block[lblock], &val, sizeof(val));
			*pblock = val;
			return 0;
		}
	}

	*pblock = lblock + 100;
	return 0;
}

ssize_t ext4_file_read(struct file *file, void *buf, size_t count,
		       loff_t *ppos)
{
	struct inode *inode = file->f_inode;
	struct ext4_sb_info *sbi = inode->i_sb->s_fs_info;
	u64 pos = *ppos;

	if (pos >= inode->i_size)
		return 0;
	if (pos + count > inode->i_size)
		count = inode->i_size - pos;

	ssize_t total = 0;
	static u8 block_buf[4096];

	while (total < count) {
		u64 pblock;
		int ret = ext4_file_get_block(inode, pos, &pblock, NULL);
		if (ret < 0)
			break;

		u32 off = pos % sbi->s_blocksize;
		size_t chunk = sbi->s_blocksize - off;
		if (chunk > count - total)
			chunk = count - total;

		ret = ext4_read_block(sbi->s_dev, sbi->s_blocksize, pblock,
				     block_buf);
		if (ret < 0)
			break;

		memcpy((u8 *)buf + total, (u8 *)block_buf + off, chunk);
		pos += chunk;
		total += chunk;
	}

	*ppos = pos;
	return total;
}

ssize_t ext4_file_write(struct file *file, const void *buf, size_t count,
			loff_t *ppos)
{
	struct inode *inode = file->f_inode;
	struct ext4_sb_info *sbi = inode->i_sb->s_fs_info;
	u64 pos = *ppos;

	size_t total = 0;
	void *block_buf = kzalloc_page();
	if (!block_buf)
		return -ENOMEM;

	while (total < count) {
		u64 pblock;
		int ret = ext4_file_get_block(inode, pos, &pblock, NULL);
		if (ret < 0) {
			ext4_file_alloc_block(inode, pos, &pblock);
		}

		u32 off = pos % sbi->s_blocksize;
		size_t chunk = sbi->s_blocksize - off;
		if (chunk > count - total)
			chunk = count - total;

		if (chunk < sbi->s_blocksize) {
			ext4_read_block(sbi->s_dev, sbi->s_blocksize, pblock,
				       block_buf);
		}

		memcpy((u8 *)block_buf + off, (const u8 *)buf + total, chunk);
		ext4_write_block(sbi->s_dev, sbi->s_blocksize, pblock,
				block_buf);

		pos += chunk;
		total += chunk;
	}

	if (pos > inode->i_size)
		inode->i_size = pos;

	// static
	*ppos = pos;
	kfree_page(block_buf);
	return total;
}

#include <fs/fd_table.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <mm/kalloc.h>
#include <sync/spinlock.h>

void fd_table_init(void) { infof("fd_table initialized"); }

struct fd_table *fd_table_alloc(void)
{
	struct fd_table *fdt = kmalloc(sizeof(struct fd_table));
	if (!fdt) {
		return NULL;
	}

	fdt->fds = kmalloc(sizeof(struct file *) * NR_OPEN_DEFAULT);
	if (!fdt->fds) {
		kfree(fdt);
		return NULL;
	}

	for (u32 i = 0; i < NR_OPEN_DEFAULT; i++) {
		fdt->fds[i] = NULL;
	}

	fdt->max_fds = NR_OPEN_DEFAULT;
	fdt->open_fds = 0;
	fdt->lock = SPINLOCK_INITIALIZER("fd_table");

	return fdt;
}

void fd_table_free(struct fd_table *fdt)
{
	if (!fdt) {
		return;
	}

	spinlock_acquire(&fdt->lock);

	for (u32 i = 0; i < fdt->max_fds; i++) {
		if (fdt->fds[i]) {
			file_put(fdt->fds[i]);
			fdt->fds[i] = NULL;
		}
	}

	kfree(fdt->fds);
	spinlock_release(&fdt->lock);
	kfree(fdt);
}

struct fd_table *fd_table_dup(struct fd_table *fdt)
{
	if (!fdt) {
		return NULL;
	}

	struct fd_table *new_fdt = fd_table_alloc();
	if (!new_fdt) {
		return NULL;
	}

	spinlock_acquire(&fdt->lock);
	spinlock_acquire(&new_fdt->lock);

	for (u32 i = 0; i < fdt->max_fds && i < new_fdt->max_fds; i++) {
		if (fdt->fds[i]) {
			file_get(fdt->fds[i]);
			new_fdt->fds[i] = fdt->fds[i];
			new_fdt->open_fds++;
		}
	}

	spinlock_release(&new_fdt->lock);
	spinlock_release(&fdt->lock);

	return new_fdt;
}

int fd_alloc(struct fd_table *fdt)
{
	if (!fdt) {
		return -EINVAL;
	}

	spinlock_acquire(&fdt->lock);

	int fd = -EMFILE;
	for (u32 i = 0; i < fdt->max_fds; i++) {
		if (!fdt->fds[i]) {
			fd = (int)i;
			fdt->open_fds++;
			break;
		}
	}

	if (fd < 0 && fdt->max_fds < NR_OPEN_MAX) {
		u32 new_max = fdt->max_fds * 2;
		if (new_max > NR_OPEN_MAX) {
			new_max = NR_OPEN_MAX;
		}

		struct file **new_fds =
		    kmalloc(sizeof(struct file *) * new_max);
		if (new_fds) {
			for (u32 i = 0; i < fdt->max_fds; i++) {
				new_fds[i] = fdt->fds[i];
			}
			for (u32 i = fdt->max_fds; i < new_max; i++) {
				new_fds[i] = NULL;
			}

			kfree(fdt->fds);
			fdt->fds = new_fds;
			fdt->max_fds = new_max;

			fd = (int)fdt->max_fds / 2;
			fdt->open_fds++;
		}
	}

	spinlock_release(&fdt->lock);
	return fd;
}

void fd_free(struct fd_table *fdt, int fd)
{
	if (!fdt || fd < 0 || (u32)fd >= fdt->max_fds) {
		return;
	}

	spinlock_acquire(&fdt->lock);

	if (fdt->fds[fd]) {
		file_put(fdt->fds[fd]);
		fdt->fds[fd] = NULL;
		fdt->open_fds--;
	}

	spinlock_release(&fdt->lock);
}

struct file *fd_get(struct fd_table *fdt, int fd)
{
	if (!fdt || fd < 0 || (u32)fd >= fdt->max_fds) {
		return NULL;
	}

	spinlock_acquire(&fdt->lock);
	struct file *file = fdt->fds[fd];
	if (file) {
		file_get(file);
	}
	spinlock_release(&fdt->lock);

	return file;
}

int fd_install(struct fd_table *fdt, int fd, struct file *file)
{
	if (!fdt || !file || fd < 0 || (u32)fd >= fdt->max_fds) {
		return -EINVAL;
	}

	spinlock_acquire(&fdt->lock);

	if (fdt->fds[fd]) {
		spinlock_release(&fdt->lock);
		return -EBADF;
	}

	fdt->fds[fd] = file;
	fdt->open_fds++;

	spinlock_release(&fdt->lock);
	return 0;
}

#include <fs/namei.h>
#include <fs/vfs.h>
#include <fs/dentry.h>
#include <fs/inode.h>
#include <fs/super.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <misc/string.h>
#include <mm/kalloc.h>
#include <task/proc.h>

static int vfs_get_name(const char *path, char *name, u32 *len)
{
	if (!path || !name || !len) {
		return -EINVAL;
	}

	u32 i = 0;
	while (path[i] && path[i] != '/' && i < NAME_MAX) {
		name[i] = path[i];
		i++;
	}

	name[i] = '\0';
	*len = i;

	return 0;
}

static const char *vfs_skip_slashes(const char *path)
{
	if (!path) {
		return NULL;
	}

	while (*path == '/') {
		path++;
	}

	return path;
}

static struct dentry *vfs_lookup_single(struct dentry *base, const char *name,
					u32 len)
{
	if (!base || !name || len == 0) {
		return PTR(EINVAL);
	}

	if (!base->d_inode || !S_ISDIR(base->d_inode->i_mode)) {
		return PTR(ENOTDIR);
	}

	if (!base->d_inode->i_op || !base->d_inode->i_op->lookup) {
		return PTR(ENOSYS);
	}

	struct qstr qstr;
	qstr.name = (char *)name;
	qstr.len = len;
	qstr.hash = hash_string(name, len);

	struct dentry *dentry = dentry_lookup(base->d_sb, base, &qstr);
	if (dentry) {
		return dentry;
	}

	dentry = dentry_alloc(base, base->d_sb, name);
	if (IS_ERR(dentry)) {
		return dentry;
	}

	struct dentry *result =
	    base->d_inode->i_op->lookup(base->d_inode, dentry);
	if (IS_ERR(result)) {
		dentry_free(dentry);
		return result;
	}

	if (!result) {
		dentry_free(dentry);
		return PTR(ENOENT);
	}

	if (result != dentry) {
		dentry_free(dentry);
		dentry = result;
	}

	dentry_insert(dentry);
	return dentry;
}

int vfs_path_walk(struct nameidata *nd, const char *path)
{
	if (!nd || !path) {
		return -EINVAL;
	}

	struct dentry *dentry = nd->dentry;
	if (!dentry) {
		return -ENOENT;
	}

	path = vfs_skip_slashes(path);
	if (!*path) {
		nd->dentry = dentry;
		nd->inode = dentry->d_inode;
		return 0;
	}

	static char name[NAME_MAX + 1];
	u32 len;
	int first = 1;

	while (*path) {
		int ret = vfs_get_name(path, name, &len);
		if (ret < 0) {
			if (!first)
				dentry_put(dentry);
			return ret;
		}

		if (strcmp(name, ".") == 0) {
			nd->last_type = LAST_DOT;
		} else if (strcmp(name, "..") == 0) {
			nd->last_type = LAST_DOTDOT;
			if (dentry->d_parent && dentry->d_parent != dentry) {
				struct dentry *parent = dentry->d_parent;
				dentry_get(parent);
				if (!first)
					dentry_put(dentry);
				dentry = parent;
			}
		} else {
			nd->last_type = LAST_NORM;

			struct dentry *next =
			    vfs_lookup_single(dentry, name, len);
			if (IS_ERR(next)) {
				if (!first)
					dentry_put(dentry);
				return PTR_ERR(next);
			}

			if (!first)
				dentry_put(dentry);
			dentry = next;
		}
		first = 0;

		path += len;
		path = vfs_skip_slashes(path);

		if (!*path) {
			break;
		}

		if (!dentry->d_inode || !S_ISDIR(dentry->d_inode->i_mode)) {
			dentry_put(dentry);
			return -ENOTDIR;
		}
	}

	nd->dentry = dentry;
	nd->inode = dentry->d_inode;

	qstr_init(&nd->last, name);

	return 0;
}

struct dentry *vfs_path_lookup(struct dentry *base, const char *path, u32 flags)
{
	if (!path) {
		return PTR(EINVAL);
	}

	/* absolute paths always start from the root */
	if (path[0] == '/') {
		base = vfs_get_root();
		if (!base) {
			return PTR(ENOENT);
		}
	} else if (!base) {
		base = thiscpu()->proc->pwd;
		if (!base) {
			base = vfs_get_root();
		}
		if (!base) {
			return PTR(ENOENT);
		}
	}

	dentry_get(base);

	struct nameidata nd;
	nd.dentry = base;
	nd.inode = base->d_inode;
	nd.flags = flags;
	nd.last_type = LAST_NORM;
	nd.depth = 0;

	int ret = vfs_path_walk(&nd, path);
	if (ret < 0) {
		dentry_put(base);
		return PTR(-(long)ret);
	}

	/* follow symlinks (max 8 hops) */
	int follow = 0;
	while (nd.inode && S_ISLNK(nd.inode->i_mode) && follow < 8) {
		if (!nd.inode->i_op || !nd.inode->i_op->readlink)
			break;

		char target[PATH_MAX];
		int len = nd.inode->i_op->readlink(nd.inode, target,
						   PATH_MAX - 1);
		if (len <= 0)
			break;
		target[len] = '\0';

		struct dentry *sym_dentry = nd.dentry;
		struct dentry *new_base;

		if (target[0] == '/') {
			/* absolute symlink: restart from root */
			new_base = vfs_get_root();
		} else {
			/* relative symlink: resolve from symlink's parent */
			new_base = sym_dentry->d_parent;
		}
		if (!new_base) {
			ret = -ENOENT;
			break;
		}

		dentry_get(new_base);
		struct nameidata nd2;
		nd2.dentry = new_base;
		nd2.inode = new_base->d_inode;
		nd2.flags = flags;
		nd2.last_type = LAST_NORM;
		nd2.depth = 0;

		ret = vfs_path_walk(&nd2, target);
		dentry_put(new_base);
		if (ret < 0)
			break;

		dentry_put(nd.dentry);
		nd.dentry = nd2.dentry;
		nd.inode = nd2.inode;
		follow++;
	}

	dentry_put(base);
	if (ret < 0) {
		dentry_put(nd.dentry);
		return PTR(-(long)ret);
	}
	return nd.dentry;
}

struct dentry *vfs_lookup_one_len(struct dentry *base, const char *name,
				  u32 len)
{
	if (!base || !name || len == 0) {
		return PTR(EINVAL);
	}

	return vfs_lookup_single(base, name, len);
}

int vfs_path_parent(struct dentry *base, const char *path, struct path *parent,
		    struct qstr *last)
{
	if (!path || !parent || !last) {
		return -EINVAL;
	}

	if (!base) {
		base = thiscpu()->proc->pwd;
		if (!base) {
			base = vfs_get_root();
		}
		if (!base) {
			return -ENOENT;
		}
	}

	dentry_get(base);

	static char name[NAME_MAX + 1];
	u32 len;

	const char *p = path;
	const char *last_start = NULL;
	struct dentry *current = base;

	p = vfs_skip_slashes(p);

	while (*p) {
		last_start = p;

		int ret = vfs_get_name(p, name, &len);
		if (ret < 0) {
			dentry_put(base);
			return ret;
		}

		p += len;
		p = vfs_skip_slashes(p);

		if (*p) {
			struct dentry *next =
			    vfs_lookup_single(current, name, len);
			if (IS_ERR(next)) {
				dentry_put(base);
				return PTR_ERR(next);
			}

			if (current != base) {
				dentry_put(current);
			}
			current = next;
		}
	}

	parent->dentry = current;
	parent->inode = current->d_inode;

	if (last_start) {
		vfs_get_name(last_start, name, &len);
		qstr_init(last, name);
	} else {
		qstr_init(last, "");
	}

	return 0;
}

#include <fs/file.h>
#include <fs/inode.h>
#include <fs/dentry.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <mm/slab.h>
#include <mm/kalloc.h>
#include <sync/spinlock.h>

static struct kmem_cache file_cache;

static struct {
	struct list_head file_list;
	spinlock_t lock;
	u32 count;
} file_state;

void file_init(void)
{
	if (kmem_cache_init(&file_cache, "file", sizeof(struct file), false) !=
	    0) {
		panic("file_init: failed to create cache");
	}

	INIT_LIST_HEAD(&file_state.file_list);
	file_state.lock = SPINLOCK_INITIALIZER("file");
	file_state.count = 0;

	infof("file initialized");
}

struct file *file_alloc(void)
{
	struct file *file = kzalloc(sizeof(struct file));
	if (!file) {
		return PTR(ENOMEM);
	}

	file->f_refcnt = 1;
	file->f_lock = SPINLOCK_INITIALIZER("file");
	INIT_LIST_HEAD(&file->f_list);

	spinlock_acquire(&file_state.lock);
	list_add(&file->f_list, &file_state.file_list);
	file_state.count++;
	spinlock_release(&file_state.lock);

	return file;
}

void file_free(struct file *file)
{
	if (!file) {
		return;
	}

	spinlock_acquire(&file_state.lock);
	list_del(&file->f_list);
	file_state.count--;
	spinlock_release(&file_state.lock);

	kmem_cache_free(file);
}

struct file *file_open(struct dentry *dentry, u32 flags)
{
	struct file *file = file_alloc();
	if (IS_ERR(file)) {
		return file;
	}

	file->f_dentry = dentry;
	file->f_inode = dentry->d_inode;
	file->f_flags = flags;
	file->f_op = dentry->d_inode->i_fop;

	if (S_ISDIR(dentry->d_inode->i_mode)) {
		file->f_mode = S_IFDIR;
	} else if (S_ISREG(dentry->d_inode->i_mode)) {
		file->f_mode = S_IFREG;
	}

	dentry_get(dentry);

	if (file->f_op && file->f_op->open) {
		int ret = file->f_op->open(dentry->d_inode, file);
		if (ret < 0) {
			dentry_put(dentry);
			file_free(file);
			return PTR((long)ret);
		}
	}

	return file;
}

int file_close(struct file *file)
{
	if (!file) {
		return -EINVAL;
	}

	spinlock_acquire(&file->f_lock);
	file->f_refcnt--;

	if (file->f_refcnt == 0) {
		spinlock_release(&file->f_lock);

		if (file->f_op && file->f_op->release) {
			file->f_op->release(file->f_inode, file);
		}

		if (file->f_dentry) {
			dentry_put(file->f_dentry);
		}

		file_free(file);
		return 0;
	}

	spinlock_release(&file->f_lock);
	return 0;
}

ssize_t file_read(struct file *file, void *buf, size_t count)
{
	if (!file || !buf || count == 0) {
		return -EINVAL;
	}

	if (!file->f_op || !file->f_op->read) {
		return -ENOSYS;
	}

	if (!file->f_inode) {
		return file->f_op->read(file, buf, count, &file->f_pos);
	}

	if ((file->f_flags & O_ACCMODE) == O_WRONLY) {
		return -EACCES;
	}

	if (S_ISDIR(file->f_inode->i_mode)) {
		return -EISDIR;
	}

	spinlock_acquire(&file->f_lock);

	loff_t pos = file->f_pos;
	if (pos >= file->f_inode->i_size) {
		spinlock_release(&file->f_lock);
		return 0;
	}

	if (pos + count > file->f_inode->i_size) {
		count = file->f_inode->i_size - pos;
	}

	ssize_t ret = file->f_op->read(file, buf, count, &pos);
	if (ret > 0) {
		file->f_pos = pos;
	}

	spinlock_release(&file->f_lock);
	return ret;
}

ssize_t file_write(struct file *file, const void *buf, size_t count)
{
	if (!file || !buf || count == 0) {
		return -EINVAL;
	}

	if (!file->f_op || !file->f_op->write) {
		return -ENOSYS;
	}

	if (!file->f_inode) {
		return file->f_op->write(file, buf, count, &file->f_pos);
	}

	if ((file->f_flags & O_ACCMODE) == O_RDONLY) {
		return -EACCES;
	}

	if (S_ISDIR(file->f_inode->i_mode)) {
		return -EISDIR;
	}

	spinlock_acquire(&file->f_lock);

	loff_t pos = file->f_pos;

	if (file->f_flags & O_APPEND) {
		pos = file->f_inode->i_size;
	}

	ssize_t ret = file->f_op->write(file, buf, count, &pos);
	if (ret > 0) {
		file->f_pos = pos;
		if (pos > file->f_inode->i_size) {
			file->f_inode->i_size = pos;
		}
	}

	spinlock_release(&file->f_lock);
	return ret;
}

loff_t file_lseek(struct file *file, loff_t offset, int whence)
{
	if (!file) {
		return -EINVAL;
	}

	if (!file->f_inode) {
		return -ENOENT;
	}

	if (S_ISDIR(file->f_inode->i_mode)) {
		return -EISDIR;
	}

	spinlock_acquire(&file->f_lock);

	loff_t new_pos;
	switch (whence) {
	case SEEK_SET:
		new_pos = offset;
		break;
	case SEEK_CUR:
		new_pos = file->f_pos + offset;
		break;
	case SEEK_END:
		new_pos = file->f_inode->i_size + offset;
		break;
	default:
		spinlock_release(&file->f_lock);
		return -EINVAL;
	}

	if (new_pos < 0) {
		spinlock_release(&file->f_lock);
		return -EINVAL;
	}

	if (file->f_op && file->f_op->llseek) {
		new_pos = file->f_op->llseek(file, offset, whence);
		if (new_pos < 0) {
			spinlock_release(&file->f_lock);
			return new_pos;
		}
	}

	file->f_pos = new_pos;
	spinlock_release(&file->f_lock);
	return new_pos;
}

void file_get(struct file *file)
{
	if (!file) {
		return;
	}

	spinlock_acquire(&file->f_lock);
	file->f_refcnt++;
	spinlock_release(&file->f_lock);
}

void file_put(struct file *file)
{
	if (!file) {
		return;
	}

	spinlock_acquire(&file->f_lock);
	file->f_refcnt--;

	if (file->f_refcnt == 0) {
		spinlock_release(&file->f_lock);

		if (file->f_op && file->f_op->release)
			file->f_op->release(file->f_inode, file);

		if (file->f_dentry)
			dentry_put(file->f_dentry);

		file_free(file);
		return;
	}

	spinlock_release(&file->f_lock);
}

#include <fs/inode.h>
#include <fs/super.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <misc/hashtable.h>
#include <mm/slab.h>
#include <sync/spinlock.h>

static struct kmem_cache inode_cache;

static struct {
	struct hashtable ht;
	struct list_head inode_list;
	spinlock_t lock;
	u32 count;
} inode_state;

void inode_init(void)
{
	if (kmem_cache_init(&inode_cache, "inode", sizeof(struct inode),
			    false) != 0) {
		panic("inode_init: failed to create cache");
	}

	if (hashtable_init(&inode_state.ht, 64) != 0) {
		panic("inode_init: failed to init hashtable");
	}

	INIT_LIST_HEAD(&inode_state.inode_list);
	inode_state.lock = SPINLOCK_INITIALIZER("inode");
	inode_state.count = 0;

	infof("inode initialized");
}

struct inode *inode_alloc(struct super_block *sb)
{
	struct inode *inode = kmem_cache_alloc(&inode_cache);
	if (!inode) {
		return PTR(ENOMEM);
	}

	inode->i_ino = 0;
	inode->i_mode = 0;
	inode->i_uid = 0;
	inode->i_gid = 0;
	inode->i_size = 0;
	inode->i_blocks = 0;
	inode->i_atime = 0;
	inode->i_mtime = 0;
	inode->i_ctime = 0;
	inode->i_nlink = 1;
	inode->i_rdev = 0;

	inode->i_sb = sb;
	inode->i_op = NULL;
	inode->i_fop = NULL;
	inode->i_mapping = NULL;
	inode->i_private = NULL;

	INIT_LIST_HEAD(&inode->i_list);
	INIT_LIST_HEAD(&inode->i_dentry);
	inode->i_lock = SPINLOCK_INITIALIZER("inode");
	inode->i_refcnt = 1;
	inode->i_state = I_NEW;

	if (sb && sb->s_op && sb->s_op->alloc_inode) {
		struct inode *alloced = sb->s_op->alloc_inode(sb);
		if (IS_ERR(alloced)) {
			kmem_cache_free(inode);
			return alloced;
		}
		if (alloced) {
			kmem_cache_free(inode);
			return alloced;
		}
	}

	return inode;
}

void inode_free(struct inode *inode)
{
	if (!inode) {
		return;
	}

	if (inode->i_sb && inode->i_sb->s_op &&
	    inode->i_sb->s_op->destroy_inode) {
		inode->i_sb->s_op->destroy_inode(inode);
		return;
	}

	spinlock_acquire(&inode_state.lock);
	hashtable_delete(&inode_state.ht, (void *)inode->i_ino);
	list_del(&inode->i_list);
	inode_state.count--;
	spinlock_release(&inode_state.lock);

	kmem_cache_free(inode);
}

struct inode *inode_get(struct super_block *sb, ino_t ino)
{
	spinlock_acquire(&inode_state.lock);

	struct inode *inode = hashtable_lookup(&inode_state.ht, (void *)ino);
	if (inode) {
		inode->i_refcnt++;
		spinlock_release(&inode_state.lock);
		return inode;
	}

	spinlock_release(&inode_state.lock);

	inode = inode_alloc(sb);
	if (IS_ERR(inode)) {
		return inode;
	}

	inode->i_ino = ino;

	spinlock_acquire(&inode_state.lock);
	hashtable_insert(&inode_state.ht, (void *)ino, inode);
	list_add(&inode->i_list, &inode_state.inode_list);
	inode_state.count++;
	spinlock_release(&inode_state.lock);

	return inode;
}

void inode_put(struct inode *inode)
{
	if (!inode) {
		return;
	}

	spinlock_acquire(&inode->i_lock);
	inode->i_refcnt--;

	if (inode->i_refcnt == 0) {
		spinlock_release(&inode->i_lock);

		if (inode->i_sb && inode->i_sb->s_op &&
		    inode->i_sb->s_op->drop_inode) {
			if (inode->i_sb->s_op->drop_inode(inode) != 0) {
				return;
			}
		}

		inode_free(inode);
		return;
	}

	spinlock_release(&inode->i_lock);
}

struct inode *inode_lookup(ino_t ino)
{
	spinlock_acquire(&inode_state.lock);
	struct inode *inode = hashtable_lookup(&inode_state.ht, (void *)ino);
	spinlock_release(&inode_state.lock);
	return inode;
}

void inode_dirty(struct inode *inode)
{
	if (!inode) {
		return;
	}

	spinlock_acquire(&inode->i_lock);
	inode->i_state |= I_DIRTY;

	if (inode->i_sb && inode->i_sb->s_op &&
	    inode->i_sb->s_op->dirty_inode) {
		inode->i_sb->s_op->dirty_inode(inode);
	}

	spinlock_release(&inode->i_lock);
}

int inode_write(struct inode *inode)
{
	if (!inode) {
		return -EINVAL;
	}

	spinlock_acquire(&inode->i_lock);

	if (!(inode->i_state & I_DIRTY)) {
		spinlock_release(&inode->i_lock);
		return 0;
	}

	if (!inode->i_sb || !inode->i_sb->s_op ||
	    !inode->i_sb->s_op->write_inode) {
		spinlock_release(&inode->i_lock);
		return -ENOSYS;
	}

	int ret = inode->i_sb->s_op->write_inode(inode);
	if (ret == 0) {
		inode->i_state &= ~I_DIRTY;
	}

	spinlock_release(&inode->i_lock);
	return ret;
}

void inode_truncate(struct inode *inode)
{
	if (!inode) {
		return;
	}

	spinlock_acquire(&inode->i_lock);
	inode->i_size = 0;
	inode->i_blocks = 0;
	inode_dirty(inode);
	spinlock_release(&inode->i_lock);
}

#include <fs/super.h>
#include <fs/vfs.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <mm/kalloc.h>
#include <mm/slab.h>
#include <sync/spinlock.h>

static struct kmem_cache super_cache;

static struct {
	struct list_head super_list;
	spinlock_t lock;
	u32 count;
} super_state;

void super_init(void)
{
	if (kmem_cache_init(&super_cache, "super_block",
			    sizeof(struct super_block), false) != 0) {
		panic("super_init: failed to create cache");
	}

	INIT_LIST_HEAD(&super_state.super_list);
	super_state.lock = SPINLOCK_INITIALIZER("super");
	super_state.count = 0;

	infof("superblock initialized");
}

struct super_block *super_alloc(struct file_system_type *type, dev_t dev)
{
	struct super_block *sb = kmem_cache_alloc(&super_cache);
	if (!sb) {
		return PTR(ENOMEM);
	}

	sb->s_dev = dev;
	sb->s_type = type;
	sb->s_root = NULL;
	sb->s_op = NULL;
	sb->s_fs_info = NULL;
	INIT_LIST_HEAD(&sb->s_list);
	INIT_LIST_HEAD(&sb->s_inodes);
	sb->s_lock = SPINLOCK_INITIALIZER("super_block");
	sb->s_maxbytes = 0;
	sb->s_blocksize = BLOCK_SIZE;
	sb->s_blocksize_bits = 9;
	sb->s_flags = 0;
	sb->s_count = 1;

	return sb;
}

void super_free(struct super_block *sb)
{
	if (!sb) {
		return;
	}

	spinlock_acquire(&super_state.lock);
	list_del(&sb->s_list);
	super_state.count--;
	spinlock_release(&super_state.lock);

	kmem_cache_free(sb);
}

struct super_block *super_lookup(dev_t dev)
{
	spinlock_acquire(&super_state.lock);

	struct super_block *sb;
	list_for_each_entry(sb, &super_state.super_list, s_list)
	{
		if (sb->s_dev == dev) {
			spinlock_release(&super_state.lock);
			return sb;
		}
	}

	spinlock_release(&super_state.lock);
	return NULL;
}

void super_get(struct super_block *sb)
{
	if (!sb) {
		return;
	}

	spinlock_acquire(&sb->s_lock);
	sb->s_count++;
	spinlock_release(&sb->s_lock);
}

void super_put(struct super_block *sb)
{
	if (!sb) {
		return;
	}

	spinlock_acquire(&sb->s_lock);
	sb->s_count--;

	if (sb->s_count == 0) {
		spinlock_release(&sb->s_lock);

		if (sb->s_op && sb->s_op->put_super) {
			sb->s_op->put_super(sb);
		}

		super_free(sb);
		return;
	}

	spinlock_release(&sb->s_lock);
}

int super_register(struct super_block *sb)
{
	if (!sb) {
		return -EINVAL;
	}

	spinlock_acquire(&super_state.lock);

	struct super_block *existing;
	list_for_each_entry(existing, &super_state.super_list, s_list)
	{
		if (existing->s_dev == sb->s_dev) {
			spinlock_release(&super_state.lock);
			return -EEXIST;
		}
	}

	list_add(&sb->s_list, &super_state.super_list);
	super_state.count++;

	spinlock_release(&super_state.lock);
	return 0;
}

void super_unregister(struct super_block *sb)
{
	if (!sb) {
		return;
	}

	spinlock_acquire(&super_state.lock);
	list_del(&sb->s_list);
	super_state.count--;
	spinlock_release(&super_state.lock);
}

#include <fs/dentry.h>
#include <fs/inode.h>
#include <fs/super.h>
#include <misc/log.h>
#include <misc/errno.h>
#include <misc/complier.h>
#include <misc/string.h>
#include <misc/hashtable.h>
#include <mm/slab.h>
#include <mm/kalloc.h>
#include <sync/spinlock.h>

static struct kmem_cache dentry_cache;

static struct {
	struct hashtable ht;
	struct list_head dentry_list;
	struct list_head dentry_lru;
	spinlock_t lock;
	u32 count;
} dentry_state;

static u32 dentry_hash_key(struct super_block *sb, struct dentry *parent,
			   struct qstr *name)
{
	u32 hash = (u32)((uintptr_t)sb ^ (uintptr_t)parent);
	hash = hash ^ name->hash;
	return hash_ptr((void *)(uintptr_t)hash, dentry_state.ht.size);
}

void dentry_init(void)
{
	if (kmem_cache_init(&dentry_cache, "dentry", sizeof(struct dentry),
			    false) != 0) {
		panic("dentry_init: failed to create cache");
	}

	if (hashtable_init(&dentry_state.ht, 128) != 0) {
		panic("dentry_init: failed to init hashtable");
	}

	INIT_LIST_HEAD(&dentry_state.dentry_list);
	INIT_LIST_HEAD(&dentry_state.dentry_lru);
	dentry_state.lock = SPINLOCK_INITIALIZER("dentry");
	dentry_state.count = 0;

	infof("dentry initialized");
}

struct dentry *dentry_alloc(struct dentry *parent, struct super_block *sb,
			    const char *name)
{
	struct dentry *dentry = kmem_cache_alloc(&dentry_cache);
	if (!dentry) {
		return PTR(ENOMEM);
	}

	char *name_copy = kmalloc(strlen(name) + 1);
	if (!name_copy) {
		kmem_cache_free(dentry);
		return PTR(ENOMEM);
	}
	strcpy(name_copy, name);

	dentry->d_name.name = name_copy;
	dentry->d_name.len = strlen(name);
	dentry->d_name.hash = hash_string(name, dentry->d_name.len);

	dentry->d_inode = NULL;
	dentry->d_sb = sb;
	dentry->d_parent = parent ? parent : dentry;
	dentry->d_op = NULL;
	dentry->d_fsdata = NULL;

	INIT_LIST_HEAD(&dentry->d_children);
	INIT_LIST_HEAD(&dentry->d_sibling);
	INIT_LIST_HEAD(&dentry->d_lru);
	INIT_LIST_HEAD(&dentry->d_hash);
	INIT_LIST_HEAD(&dentry->d_list);
	dentry->d_lock = SPINLOCK_INITIALIZER("dentry");
	dentry->d_refcnt = 1;
	dentry->d_flags = 0;

	if (parent) {
		spinlock_acquire(&parent->d_lock);
		list_add(&dentry->d_sibling, &parent->d_children);
		spinlock_release(&parent->d_lock);
	}

	return dentry;
}

void dentry_free(struct dentry *dentry)
{
	if (!dentry) {
		return;
	}

	if (dentry->d_op && dentry->d_op->d_release) {
		dentry->d_op->d_release(dentry);
	}

	spinlock_acquire(&dentry_state.lock);
	hashtable_delete(&dentry_state.ht,
			 (void *)(uintptr_t)dentry_hash_key(
			     dentry->d_sb, dentry->d_parent, &dentry->d_name));
	list_del(&dentry->d_list);
	list_del(&dentry->d_lru);
	dentry_state.count--;
	spinlock_release(&dentry_state.lock);

	if (dentry->d_parent && dentry->d_parent != dentry) {
		spinlock_acquire(&dentry->d_parent->d_lock);
		list_del(&dentry->d_sibling);
		spinlock_release(&dentry->d_parent->d_lock);
	}

	if (dentry->d_inode) {
		inode_put(dentry->d_inode);
	}

	if (dentry->d_name.name) {
		kfree(dentry->d_name.name);
	}

	kmem_cache_free(dentry);
}

struct dentry_match_arg {
	struct super_block *sb;
	struct dentry *parent;
	struct qstr *name;
};

static int dentry_match(void *value, void *arg)
{
	struct dentry *d = value;
	struct dentry_match_arg *ma = arg;
	return d->d_sb == ma->sb && d->d_parent == ma->parent &&
	       d->d_name.len == ma->name->len &&
	       memcmp(d->d_name.name, ma->name->name, ma->name->len) == 0;
}

struct dentry *dentry_lookup(struct super_block *sb, struct dentry *parent,
			     struct qstr *name)
{
	spinlock_acquire(&dentry_state.lock);

	u32 key = dentry_hash_key(sb, parent, name);
	struct dentry_match_arg arg = { sb, parent, name };
	struct dentry *dentry =
	    hashtable_lookup_match(&dentry_state.ht, (void *)(uintptr_t)key,
				   dentry_match, &arg);

	spinlock_release(&dentry_state.lock);

	// if (dentry) {
	// 	printf("dentry_lookup: q='%s' HIT cached='%s'\n",
	// 	       name->name, dentry->d_name.name);
	// 	dentry_get(dentry);
	// } else {
	// 	printf("dentry_lookup: q='%s' MISS\n", name->name);
	// }

	return dentry;
}

void dentry_put(struct dentry *dentry)
{
	if (!dentry) {
		return;
	}

	spinlock_acquire(&dentry->d_lock);
	if (dentry->d_refcnt == 0) {
		spinlock_release(&dentry->d_lock);
		// errorf("dcache refcount underflow on %s!", dentry->d_name.name);
		return;
	}
	dentry->d_refcnt--;

	if (dentry->d_refcnt == 0) {
		spinlock_release(&dentry->d_lock);

		spinlock_acquire(&dentry_state.lock);
		list_add(&dentry->d_lru, &dentry_state.dentry_lru);
		spinlock_release(&dentry_state.lock);
		return;
	}

	spinlock_release(&dentry->d_lock);
}

void dentry_get(struct dentry *dentry)
{
	if (!dentry) {
		return;
	}

	spinlock_acquire(&dentry->d_lock);
	dentry->d_refcnt++;
	spinlock_release(&dentry->d_lock);
}

int dentry_insert(struct dentry *dentry)
{
	if (!dentry) {
		return -EINVAL;
	}

	spinlock_acquire(&dentry_state.lock);

	u32 key =
	    dentry_hash_key(dentry->d_sb, dentry->d_parent, &dentry->d_name);
	struct dentry *existing =
	    hashtable_lookup(&dentry_state.ht, (void *)(uintptr_t)key);
	if (existing) {
		spinlock_release(&dentry_state.lock);
		return -EEXIST;
	}

	hashtable_insert(&dentry_state.ht, (void *)(uintptr_t)key, dentry);
	list_add(&dentry->d_list, &dentry_state.dentry_list);
	dentry_state.count++;

	spinlock_release(&dentry_state.lock);
	return 0;
}

void dentry_delete(struct dentry *dentry)
{
	if (!dentry) {
		return;
	}

	if (dentry->d_op && dentry->d_op->d_delete) {
		if (dentry->d_op->d_delete(dentry) != 0) {
			return;
		}
	}

	spinlock_acquire(&dentry_state.lock);
	hashtable_delete(&dentry_state.ht,
			 (void *)(uintptr_t)dentry_hash_key(
			     dentry->d_sb, dentry->d_parent, &dentry->d_name));
	spinlock_release(&dentry_state.lock);

	if (dentry->d_inode) {
		inode_put(dentry->d_inode);
		dentry->d_inode = NULL;
	}

	dentry_put(dentry);
}

struct dentry *dentry_root(struct super_block *sb)
{
	struct dentry *root = dentry_alloc(NULL, sb, "/");
	if (IS_ERR(root)) {
		return root;
	}

	root->d_parent = root;

	if (dentry_insert(root) != 0) {
		dentry_free(root);
		return PTR(EEXIST);
	}

	return root;
}

#include <hal/blk.h>
#include <misc/log.h>
#include <misc/string.h>
#include <mm/kalloc.h>

#define BLK_MAX_DEVICES 16

static struct {
	struct block_device *devices[BLK_MAX_DEVICES];
	u32 count;
	spinlock_t lock;
} blk_registry;

void blk_init(void)
{
	blk_registry.count = 0;
	blk_registry.lock = SPINLOCK_INITIALIZER("blk_registry");
	for (int i = 0; i < BLK_MAX_DEVICES; i++) {
		blk_registry.devices[i] = NULL;
	}
}

int blk_register(struct block_device *dev)
{
	spinlock_acquire(&blk_registry.lock);

	if (blk_registry.count >= BLK_MAX_DEVICES) {
		spinlock_release(&blk_registry.lock);
		errorf("blk_register: too many devices");
		return -1;
	}

	u32 major = MAJOR(dev->devno);
	u32 minor = MINOR(dev->devno);

	for (int i = 0; i < blk_registry.count; i++) {
		if (blk_registry.devices[i]->devno == dev->devno) {
			spinlock_release(&blk_registry.lock);
			warnf("blk_register: device %d:%d already registered",
			      major, minor);
			return -1;
		}
	}

	blk_registry.devices[blk_registry.count++] = dev;

	spinlock_release(&blk_registry.lock);

	infof("blk_register: device %d:%d (%s) registered", major, minor,
	      dev->name);
	return 0;
}

struct block_device *blk_lookup(dev_t devno)
{
	spinlock_acquire(&blk_registry.lock);

	for (int i = 0; i < blk_registry.count; i++) {
		if (blk_registry.devices[i]->devno == devno) {
			struct block_device *dev = blk_registry.devices[i];
			spinlock_release(&blk_registry.lock);
			return dev;
		}
	}

	spinlock_release(&blk_registry.lock);
	return NULL;
}

struct block_device *blk_get(dev_t devno) { return blk_lookup(devno); }

int blk_read(dev_t devno, u64 sector, void *buf, u32 nsectors)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev) {
		errorf("blk_read: device %d:%d not found", MAJOR(devno),
		       MINOR(devno));
		return -1;
	}

	if (!dev->ops || !dev->ops->read) {
		errorf("blk_read: device %s has no read operation", dev->name);
		return -1;
	}

	spinlock_acquire(&dev->lock);
	int ret = dev->ops->read(dev, sector, buf, nsectors);
	spinlock_release(&dev->lock);

	return ret;
}

int blk_write(dev_t devno, u64 sector, const void *buf, u32 nsectors)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev) {
		errorf("blk_write: device %d:%d not found", MAJOR(devno),
		       MINOR(devno));
		return -1;
	}

	if (!dev->ops || !dev->ops->write) {
		errorf("blk_write: device %s has no write operation",
		       dev->name);
		return -1;
	}

	spinlock_acquire(&dev->lock);
	int ret = dev->ops->write(dev, sector, buf, nsectors);
	spinlock_release(&dev->lock);

	return ret;
}

int blk_flush(dev_t devno)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev) {
		return -1;
	}

	if (!dev->ops || !dev->ops->flush) {
		return 0;
	}

	spinlock_acquire(&dev->lock);
	int ret = dev->ops->flush(dev);
	spinlock_release(&dev->lock);

	return ret;
}

u64 blk_capacity(dev_t devno)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev || !dev->ops || !dev->ops->get_capacity) {
		return 0;
	}
	return dev->ops->get_capacity(dev);
}

u32 blk_block_size(dev_t devno)
{
	struct block_device *dev = blk_lookup(devno);
	if (!dev || !dev->ops || !dev->ops->get_block_size) {
		return BLOCK_SIZE;
	}
	return dev->ops->get_block_size(dev);
}

#include "device.h"
#include <hal/blk.h>
#include <hal/plic.h>
#include <hal/riscv.h>
#include <hal/device_types.h>
#include <mm/bcache.h>
#include <mm/vm.h>
#include <config.h>
#include <misc/string.h>
#include <misc/log.h>
#include <sync/barrier.h>
#include <mm/kalloc.h>
#include <hal/uart.h>

struct virtio_blk_request {
	struct virtio_blk_req hdr;
	void *data;
	u8 status;
	u32 nsectors;
	bool completed;
};

struct virtio_blk_device {
	struct virtio_device vdev;
	struct block_device blk_dev;
	u64 capacity;
	u32 block_size;
};

static struct virtio_blk_device *virtio_blk;

/* BSS-allocated contiguous pool for virtqueue rings.
 * Guaranteed identity-mapped by kvminit -> kmappages(KVM(s_data), ...). */
static char virtio_vq_pool[3 * PAGE_SIZE] __attribute__((aligned(PAGE_SIZE)));

/* Static request for single-threaded boot-time I/O */
static struct virtio_blk_request virtio_req;

static int virtio_blk_rw(struct block_device *dev, u64 sector, void *buf,
			 u32 nsectors, bool write);
static int virtio_blk_flush(struct block_device *dev);
static u64 virtio_blk_capacity(struct block_device *dev);
static u32 virtio_blk_block_size(struct block_device *dev);

static struct blk_operations virtio_blk_ops = {
    .read = NULL,
    .write = NULL,
    .flush = virtio_blk_flush,
    .get_capacity = virtio_blk_capacity,
    .get_block_size = virtio_blk_block_size,
};

static int virtio_blk_rw_internal(struct block_device *dev, u64 sector,
				  void *buf, u32 nsectors, bool write)
{
	struct virtio_blk_device *blk_dev = dev->private;
	struct virtio_device *vdev = &blk_dev->vdev;
	struct virtq *vq = vdev->vqs[0];

	if (!vq) {
		errorf("virtio_blk_rw: no virtqueue");
		return -1;
	}

	if (sector + nsectors > blk_dev->capacity) {
		errorf("virtio_blk_rw: sector overflow "
		       "sector=%llu nsectors=%u capacity=%llu",
		       sector, nsectors, blk_dev->capacity);
		return -1;
	}

	struct virtio_blk_request *req = &virtio_req;
	memset(req, 0, sizeof(*req));

	req->hdr.type = write ? VIRTIO_BLK_T_OUT : VIRTIO_BLK_T_IN;
	req->hdr.reserved = 0;
	req->hdr.sector = sector;
	req->data = buf;
	req->nsectors = nsectors;
	req->status = VIRTIO_BLK_S_IOERR;
	req->completed = false;

	struct virtq_buf in_bufs[2];
	struct virtq_buf out_bufs[2];
	int n_in, n_out;

	if (write) {
		/* WRITE: hdr + data → device-readable (in), status ← device-writable (out) */
		in_bufs[0].addr = &req->hdr;  in_bufs[0].len = sizeof(req->hdr);
		in_bufs[1].addr = buf;        in_bufs[1].len = nsectors * BLOCK_SIZE;
		out_bufs[0].addr = &req->status; out_bufs[0].len = 1;
		n_in = 2; n_out = 1;
	} else {
		/* READ: hdr → device-readable (in), data + status ← device-writable (out) */
		in_bufs[0].addr = &req->hdr;  in_bufs[0].len = sizeof(req->hdr);
		out_bufs[0].addr = buf;       out_bufs[0].len = nsectors * BLOCK_SIZE;
		out_bufs[1].addr = &req->status; out_bufs[1].len = 1;
		n_in = 1; n_out = 2;
	}

	int idx = virtq_add_buf(vq, in_bufs, n_in, out_bufs, n_out, req);
	if (idx < 0) {
