			u32 len;
			struct virtio_blk_request *done =
			    virtq_get_buf(vq, &len);
			if (done) {
				done->completed = true;
			}
		}
		if (--timeout == 0) {
			errorf("virtio_blk_rw: TIMEOUT sector=%llu ns=%u write=%d",
			       sector, nsectors, write);
			dma_rmb();
