			       vq->used->flags, vq->used->idx, vq->used_idx);
			errorf("  avail: flags=%u idx=%u",
			       vq->avail->flags, vq->avail->idx);
			errorf("  desc[0]: addr=0x%llx len=%u flags=0x%x next=%u",
			       vq->descs[0].addr, vq->descs[0].len,
			       vq->descs[0].flags, vq->descs[0].next);
			errorf("  desc[1]: addr=0x%llx len=%u flags=0x%x next=%u",
			       vq->descs[1].addr, vq->descs[1].len,
			       vq->descs[1].flags, vq->descs[1].next);
			errorf("  desc[2]: addr=0x%llx len=%u flags=0x%x next=%u",
			       vq->descs[2].addr, vq->descs[2].len,
			       vq->descs[2].flags, vq->descs[2].next);
