{
	virtio_set_status(dev, 0);
	mb();

	virtio_set_status(dev, VIRTIO_CONFIG_S_ACKNOWLEDGE);
	if (!(virtio_get_status(dev) & VIRTIO_CONFIG_S_ACKNOWLEDGE)) {
		errorf("virtio_mmio_init: ACKNOWLEDGE failed");
		return -1;
	}

	virtio_set_status(dev,
			  VIRTIO_CONFIG_S_ACKNOWLEDGE | VIRTIO_CONFIG_S_DRIVER);
	if (!(virtio_get_status(dev) & VIRTIO_CONFIG_S_DRIVER)) {
		errorf("virtio_mmio_init: DRIVER failed");
		return -1;
	}

	dev->device_id = virtio_read_reg(dev, VIRTIO_REG_DEVICE_ID);
	dev->vendor_id = virtio_read_reg(dev, VIRTIO_REG_VENDOR_ID);
	dev->version = virtio_read_reg(dev, VIRTIO_REG_VERSION);

	infof("virtio_mmio_init: device initialized, id=%d version=%u",
	      dev->device_id, dev->version);
	return 0;
}

int virtio_negotiate_features(struct virtio_device *dev, u64 required,
			      u64 rejected)
{
	u64 device_features = 0;

	/* read bank 0 (bits 0-31) */
	mmio_write32(&dev->regs->device_features_sel, 0);
	u32 dev_feat_lo = mmio_read32(&dev->regs->device_features);
	device_features = dev_feat_lo;

	/* read bank 1 (bits 32-63). On transitional devices,
	 * bank selection works even with version==1. */
	mmio_write32(&dev->regs->device_features_sel, 1);
	u32 dev_feat_hi = mmio_read32(&dev->regs->device_features);
	device_features |= (u64)dev_feat_hi << 32;

	infof("virtio: device features lo=0x%08x hi=0x%08x (full=0x%016llx)",
	      dev_feat_lo, dev_feat_hi, device_features);

	/* driver supports: device features minus rejected, plus required */
	u64 driver_features = (device_features & ~rejected) | required;

	infof("virtio: driver features = 0x%016llx", driver_features);

	/* write bank 0 (bits 0-31) */
	mmio_write32(&dev->regs->driver_features_sel, 0);
	mmio_write32(&dev->regs->driver_features,
		     (u32)(driver_features & 0xffffffff));

	/* write bank 1 (bits 32-63) unconditionally. If the device
	 * doesn't support bank selection, the sel write is ignored
	 * and this just overwrites bank 0 with the upper bits —
	 * harmless since upper bits are 0 for legacy-only devices. */
	mmio_write32(&dev->regs->driver_features_sel, 1);
	mmio_write32(&dev->regs->driver_features,
		     (u32)(driver_features >> 32));

	dev->negotiated_features = driver_features;

	/* barrier: ensure driver features are visible before FEATURES_OK */
	mb();

	/* append FEATURES_OK to status and verify */
	u32 status = mmio_read32(&dev->regs->status);
	mmio_write32(&dev->regs->status, status | VIRTIO_CONFIG_S_FEATURES_OK);
	mb();

	status = mmio_read32(&dev->regs->status);
	if (!(status & VIRTIO_CONFIG_S_FEATURES_OK)) {
		errorf("virtio: FEATURES_OK rejected (status=0x%x)", status);
		errorf("virtio: device_features=0x%016llx driver_features=0x%016llx",
		       device_features, driver_features);
		mmio_write32(&dev->regs->status, VIRTIO_CONFIG_S_FAILED);
		return -1;
	}

	infof("virtio: features negotiated OK (status=0x%x)", status);
	return 0;
}

int virtio_setup_vq(struct virtio_device *dev, u32 vq_idx, u16 num,
		    void *ext_mem)
{
	if (vq_idx >= 8) {
		errorf("virtio_setup_vq: invalid vq_idx %d", vq_idx);
		return -1;
	}

	virtio_write_reg(dev, VIRTIO_REG_QUEUE_SEL, vq_idx);
	mb();

	u32 max = virtio_read_reg(dev, VIRTIO_REG_QUEUE_NUM_MAX);
	if (num > max) {
		warnf("virtio_setup_vq: requested %d > max %d, using max", num,
		      max);
		num = max;
	}

	if (num == 0) {
		errorf("virtio_setup_vq: queue %d not available", vq_idx);
		return -1;
	}

	struct virtq *vq = virtq_create(dev->regs, vq_idx, num, ext_mem);
	if (!vq) {
		errorf("virtio_setup_vq: failed to create virtq");
		return -1;
