	mb();

	uintptr_t desc_pa = va2pa(kpagetable, (uintptr_t)vq->descs);
	uintptr_t avail_pa = va2pa(kpagetable, (uintptr_t)vq->avail);
	uintptr_t used_pa = va2pa(kpagetable, (uintptr_t)vq->used);

	if (dev->negotiated_features & VIRTIO_F_VERSION_1) {
		/* Modern (virtio 1.0): separate 64-bit addresses */
		virtio_write_reg(dev, VIRTIO_REG_QUEUE_DESC_LO,
