	dev->num_vqs++;

	infof("virtio_setup_vq: vq %d ready, num=%d, desc_pa=0x%llx avail_pa=0x%llx used_pa=0x%llx",
	      vq_idx, num, (u64)desc_pa, (u64)avail_pa, (u64)used_pa);
	return 0;
}

