		vq->descs[prev].len = out_bufs[i].len;
		vq->descs[prev].flags = VRING_DESC_F_WRITE;

		if (i < n_out - 1) {
			u16 next = virtq_alloc_desc(vq);
			vq->descs[prev].next = next;
			vq->descs[prev].flags |= VRING_DESC_F_NEXT;
			prev = next;
		}
	}

	vq->descs[prev].flags &= ~VRING_DESC_F_NEXT;
	vq->descs[prev].next = 0;

	u16 avail_idx = vq->avail_idx % vq->num;
	vq->avail->ring[avail_idx] = head;
	dma_wmb();
	vq->avail->idx = ++vq->avail_idx;

	spinlock_release(&vq->lock);

	return head;
}

void *virtq_get_buf(struct virtq *vq, u32 *len)
{
	spinlock_acquire(&vq->lock);

	dma_rmb();
	u16 used_idx = vq->used->idx;
	if (vq->used_idx == used_idx) {
		spinlock_release(&vq->lock);
		return NULL;
	}

	u16 idx = vq->used_idx % vq->num;
	u16 head = vq->used->ring[idx].id;
	if (len) {
		*len = vq->used->ring[idx].len;
	}

	void *token = vq->data[head];
	vq->data[head] = NULL;

	u16 next;
	while (vq->descs[head].flags & VRING_DESC_F_NEXT) {
		next = vq->descs[head].next;
		virtq_free_desc(vq, head);
		head = next;
	}
	virtq_free_desc(vq, head);

	vq->used_idx++;

	spinlock_release(&vq->lock);

	return token;
}

bool virtq_has_buf(struct virtq *vq)
{
	dma_rmb();
	return vq->used_idx != vq->used->idx;
}

void virtq_kick(struct virtq *vq)
{
	__asm__ __volatile__("fence iorw, iorw" ::: "memory");
	mmio_write32(&vq->regs->queue_notify, vq->queue_idx);
}

u16 virtq_desc_count(struct virtq *vq)
{
	spinlock_acquire(&vq->lock);
	u16 count = vq->num - vq->num_free;
	spinlock_release(&vq->lock);
	return count;
}

#include <ipc/pipe.h>
#include <task/sched.h>
#include <task/proc.h>
#include <misc/errno.h>
#include <mm/kalloc.h>
#include <misc/string.h>

struct pipe *pipe_alloc(void)
{
	struct pipe *pi = kzalloc(sizeof(*pi));
	if (!pi)
		return NULL;
	pi->lock = SPINLOCK_INITIALIZER("pipe");
	pi->rchan = &pi->rpos;
	pi->wchan = &pi->wpos;
	return pi;
}

ssize_t pipe_read(struct file *file, void *buf, size_t count, loff_t *pos)
{
	struct pipe *pi = file->f_private;
	spinlock_acquire(&pi->lock);

	while (pi->rpos == pi->wpos) {
		if (pi->nwriters == 0) {
			spinlock_release(&pi->lock);
			return 0;
		}
		sleep(pi->rchan, &pi->lock);
		if (thiscpu()->proc->sig_pending)
			break;
	}

	if (pi->rpos == pi->wpos) {
		spinlock_release(&pi->lock);
		if (thiscpu()->proc->sig_pending)
			return -EINTR;
		return 0;
	}

	u32 avail = pi->wpos - pi->rpos;
	size_t n = count < avail ? count : avail;
	for (size_t i = 0; i < n; i++)
		((char *)buf)[i] = pi->buf[(pi->rpos + i) % PIPE_SIZE];
	pi->rpos += n;

	spinlock_release(&pi->lock);
	return n;
}

ssize_t pipe_write(struct file *file, const void *buf, size_t count,
		   loff_t *pos)
{
	struct pipe *pi = file->f_private;
	spinlock_acquire(&pi->lock);

	for (size_t i = 0; i < count; i++) {
		while (pi->wpos - pi->rpos == PIPE_SIZE) {
			if (pi->nreaders == 0) {
				spinlock_release(&pi->lock);
				return -EPIPE;
			}
			sleep(pi->wchan, &pi->lock);
		}
		pi->buf[pi->wpos % PIPE_SIZE] = ((const char *)buf)[i];
		pi->wpos++;
	}

	wakeup(pi->rchan);
	spinlock_release(&pi->lock);
	return count;
}

int pipe_release(struct inode *inode, struct file *file)
{
	struct pipe *pi = file->f_private;
	spinlock_acquire(&pi->lock);

	if (file->f_mode & O_WRONLY) {
		pi->nwriters--;
		wakeup(pi->rchan);
	}
	if (file->f_mode & O_RDONLY) {
		pi->nreaders--;
		wakeup(pi->wchan);
	}

	pi->nref--;
	if (pi->nref == 0) {
		spinlock_release(&pi->lock);
		kfree(pi);
		return 0;
	}

	spinlock_release(&pi->lock);
	return 0;
}

#include <sync/spinlock.h>
#include <trap/trap.h>
#include <arch/cpu.h>

void spinlock_acquire_bare(spinlock_t *lock)
{
	assert(lock != NULL);

#ifdef SPINLOCK_DEBUG
	u64 hart = r_tp();
	if (lock->locked && lock->owner == hart)
		panic("recursive lock acquire: %s (hart %zu)", lock->name,
		      hart);
#endif

	intr_off();
	while (1) {
		if (__atomic_exchange_n(&lock->locked, 1, __ATOMIC_ACQUIRE) ==
		    0) {
			break;
		}
		arch_spin_hint();
	}

#ifdef SPINLOCK_DEBUG
	lock->owner = r_tp();
#endif
}

void spinlock_release_bare(spinlock_t *lock)
{
	assert(lock != NULL);
#ifdef SPINLOCK_DEBUG
	if (!lock->locked) {
		panic("release unlocked lock: %s", lock->name);
	}
	if (lock->owner != r_tp()) {
		panic("spinlock_release: wrong CPU");
	}
	lock->owner = (u64)-1;
#endif
	__atomic_store_n(&lock->locked, 0, __ATOMIC_RELEASE);
	intr_on();
}

int spinlock_holding(spinlock_t *lock)
{
	assert(lock != NULL);

#ifdef SPINLOCK_DEBUG
	u64 hart = r_tp();
	return (lock->locked && lock->owner == hart);
#else
	return lock->locked;
#endif
}

#include <config.h>
#include <hal/plic.h>
#include <misc/log.h>

#define PLIC_MAX_IRQ_NUM 1024
#define PLIC_CTX(hart, mode) ((hart) * 2 + ((mode) == 'S' ? 1 : 0))

extern struct plic_raw __plic_raw;
static volatile u32 *plic_base;

#define PLIC_PRIORITY(irqno) (*(volatile u32 *)(plic_base + (irqno)))
#define PLIC_ENABLE(ctx, word)                                                 \
	(*(volatile u32 *)(plic_base + 0x800 + (ctx) * 0x20 + (word)))
#define PLIC_THRESHOLD(ctx)                                                    \
	(*(volatile u32 *)(plic_base + 0x80000 + (ctx) * 0x400))
#define PLIC_CLAIM(ctx) (*(volatile u32 *)(plic_base + 0x80001 + (ctx) * 0x400))

#define PLIC_ADDR 0x0c000000ULL

void plic_init()
{
	plic_base = (volatile u32 *)PLIC_ADDR;
}

void plic_set_priority(u32 irqno, u32 priority)
{
	assert(irqno > 0 && irqno < PLIC_MAX_IRQ_NUM);
	PLIC_PRIORITY(irqno) = priority;
}

void plic_enable(char mode, u64 hartid, u32 irqno)
{
	assert(mode == 'S' || mode == 'M');
	assert(hartid < CPU_NUM);
	assert(irqno > 0 && irqno < PLIC_MAX_IRQ_NUM);
	u32 ctx = PLIC_CTX(hartid, mode);
	PLIC_ENABLE(ctx, irqno / 32) |= (1 << (irqno % 32));
}

void plic_disable(char mode, u64 hartid, u32 irqno)
{
	assert(mode == 'S' || mode == 'M');
	assert(hartid < CPU_NUM);
	assert(irqno > 0 && irqno < PLIC_MAX_IRQ_NUM);
	u32 ctx = PLIC_CTX(hartid, mode);
	PLIC_ENABLE(ctx, irqno / 32) &= ~(1 << (irqno % 32));
}

void plic_set_threshold(char mode, u64 hartid, u32 threshold)
{
	assert(mode == 'S' || mode == 'M');
	assert(hartid < CPU_NUM);
	PLIC_THRESHOLD(PLIC_CTX(hartid, mode)) = threshold;
}

u32 plic_claim(char mode, u64 hartid)
{
	assert(mode == 'S' || mode == 'M');
	assert(hartid < CPU_NUM);
	return PLIC_CLAIM(PLIC_CTX(hartid, mode));
}

void plic_complete(char mode, u64 hartid, u32 irqno)
{
	assert(mode == 'S' || mode == 'M');
	assert(hartid < CPU_NUM);
	assert(irqno > 0 && irqno < PLIC_MAX_IRQ_NUM);
	PLIC_CLAIM(PLIC_CTX(hartid, mode)) = irqno;
}

