/* QEMU virt CLINT: mtimecmp for hart 0 */
#define CLINT_MTIMECMP0 0x02004000ULL

static volatile tick_t kernel_tick;
static u64 last;
static u64 interval;
volatile uint64_t watchdog_ticks;
volatile bool watchdog_enabled = false;

inline tick_t tick() { return kernel_tick; }

void timer_init()
{
	interval = us_to_cputime(1000000ULL / TIMER_IRQ_HZ);
	last = arch_time_read();
	sbi_set_timer(last + interval);
	kernel_tick = last / interval;
	watchdog_ticks = 0;
	watchdog_enabled = false;
}

void handle_timer()
{
	sbi_set_timer(arch_time_read() + interval);
	uart_out_flush();

	if (watchdog_enabled) {
		watchdog_ticks++;
		if (watchdog_ticks >= WATCHDOG_TIMEOUT_TICKS) {
			uart_putchar('\n');
			uart_putchar('['); uart_putchar('W'); uart_putchar('D');
			uart_putchar(']'); uart_putchar(' ');
			uart_putchar('s'); uart_putchar('h'); uart_putchar('u');
			uart_putchar('t'); uart_putchar('d'); uart_putchar('o');
			uart_putchar('w'); uart_putchar('n'); uart_putchar('\n');
			arch_shutdown();
		}
	}
}

