struct uart_rbuf uart_rbuf;
spinlock_t uart_lock = SPINLOCK_INITIALIZER("uart");
void *uart_chan = &uart_rbuf;

void uart_init(void)
{
	uart_write_reg(UART_IER, 0);
	uart_write_reg(UART_FCR, 0);
	uart_write_reg(UART_LCR, 0x03);
	uart_write_reg(UART_IER, UART_IER_ERBI);
}

void uart_putchar(char c)
{
	if (c == '\n') {
		while (!(uart_read_reg(UART_LSR) & UART_LSR_THRE))
			;
		uart_write_reg(UART_THR, '\r');
	}
	while (!(uart_read_reg(UART_LSR) & UART_LSR_THRE))
		;
	uart_write_reg(UART_THR, c);
}

int uart_getchar(void)
{
	if (uart_read_reg(UART_LSR) & UART_LSR_DR)
		return uart_read_reg(UART_RBR);
	return -1;
}

void uart_isr(void)
{
	spinlock_acquire(&uart_lock);
	while (uart_read_reg(UART_LSR) & UART_LSR_DR) {
		char c = uart_read_reg(UART_RBR);
		u32 next = (uart_rbuf.head + 1) % UART_RBUF_SIZE;
		if (next != uart_rbuf.tail) {
			uart_rbuf.buf[uart_rbuf.head] = c;
			uart_rbuf.head = next;
		}
	}
	wakeup(uart_chan);
	spinlock_release(&uart_lock);
}

/* ── stdout output buffer: filled in ecall context, flushed from timer ISR ── */

static char uart_outbuf[UART_OUTBUF_SIZE];
static u32 uart_out_head;
static u32 uart_out_tail;
static spinlock_t uart_out_lock = SPINLOCK_INITIALIZER("uart_out");

void uart_out_putchar(char c)
{
	spinlock_acquire(&uart_out_lock);
	u32 next = (uart_out_head + 1) % UART_OUTBUF_SIZE;
	if (next != uart_out_tail) {
		uart_outbuf[uart_out_head] = c;
		uart_out_head = next;
		watchdog_ticks = 0;
	}
	spinlock_release(&uart_out_lock);
}

void uart_out_flush(void)
{
	char buf[128];
	spinlock_acquire(&uart_out_lock);
	u32 n = 0;
	while (uart_out_tail != uart_out_head && n < sizeof(buf)) {
		buf[n++] = uart_outbuf[uart_out_tail];
		uart_out_tail = (uart_out_tail + 1) % UART_OUTBUF_SIZE;
	}
	spinlock_release(&uart_out_lock);
		if (n > 0) {
			for (u32 i = 0; i < n; i++)
				sbi_console_putchar(buf[i]);
		}
}

