/* autoinit — table-driven test runner for competition disk layout.
 * Disk structure: /musl/basic/  +  /glibc/basic/  (and other groups)
 * 12 test groups: basic busybox iozone libctest libcbench lmbench
 *                 lua unixbench netperf iperf cyclictest ltp
 * Only "basic" is run; all other groups are skipped implicitly.
 */
enum {
	NR_write=64, NR_clone=220, NR_execve=221, NR_wait4=260,
	NR_exit=93, NR_shutdown=500, NR_chdir=49,
};
static inline long sc(long n,long a0,long a1,long a2,long a3,long a4){
	register long a7 asm("a7")=n;
	register long r0 asm("a0")=a0,r1 asm("a1")=a1;
	register long r2 asm("a2")=a2,r3 asm("a3")=a3,r4 asm("a4")=a4;
	asm volatile("ecall":"+r"(r0):"r"(r1),"r"(r2),"r"(r3),"r"(r4),"r"(a7));
	return r0;
}
static int sl(const char*s){int n=0;while(s[n])n++;return n;}
static void puts(const char*s){sc(NR_write,1,(long)s,sl(s),0,0);}

/* copy src to dst, return pointer to end of dst (where '\0' is) */
static char *scpy(char *dst, const char *src)
{
	while (*src) *dst++ = *src++;
	*dst = '\0';
	return dst;
}
static int strcmp(const char *a, const char *b)
{
	while (*a && *a == *b) { a++; b++; }
	return *a - *b;
}
static int strncmp(const char *a, const char *b, int n)
{
	int i = 0;
	while (i < n && *a && *a == *b) { a++; b++; i++; }
	return i == n ? 0 : *a - *b;
}

static void run(const char *path)
{
	long v[2]={(long)path,0};
	long pid=sc(NR_clone,0,0,0,0,0);
	if (pid==0){
		sc(NR_execve,(long)path,(long)v,0,0,0);
		puts("FAIL:");puts(path);puts("\n");
		sc(NR_exit,1,0,0,0,0);
	}
	if (pid>0){
		int s=0;
		long w=sc(NR_wait4,-1,(long)&s,0,0,0);
		if (w<0){puts("ECHILD ");}
		puts("[OK]\n");
	}
	if (pid<0){puts("CLONE_ERR ");}
}

static void run_execve_variant(const char *root, const char *variant)
{
	char target[128]; char *p;
	p = scpy(target, root); scpy(p, "/basic/test_echo");

	puts("  run: /"); puts(root); puts("/basic/"); puts(variant); puts("\n");

	long pid = sc(NR_clone, 0, 0, 0, 0, 0);
	if (pid == 0) {
		if (strcmp(variant, "execve_abs") == 0) {
			long v[2] = {(long)target, 0};
			sc(NR_execve, (long)target, (long)v, 0, 0, 0);
		} else if (strcmp(variant, "execve_args") == 0) {
			long v[4] = {(long)"test_echo", (long)"arg1", (long)"arg2", 0};
			sc(NR_execve, (long)"test_echo", (long)v, 0, 0, 0);
		} else if (strcmp(variant, "execve_envp") == 0) {
			long v[2] = {(long)"test_echo", 0};
			long e[2] = {(long)"VAR=hello", 0};
			sc(NR_execve, (long)"test_echo", (long)v, (long)e, 0, 0);
		}
		puts("FAIL:"); puts(variant); puts("\n");
		sc(NR_exit, 1, 0, 0, 0, 0);
	}
	if (pid > 0) {
		int s = 0;
		sc(NR_wait4, -1, (long)&s, 0, 0, 0);
		puts("[OK]\n");
	}
	if (pid < 0) { puts("CLONE_ERR "); }
}

