static const char *libc_roots[] = {"/musl", "/glibc", 0};

/* build "/musl/basic/brk" into buf[128], returns buf */
static char *mkpath(char *buf, const char *root, const char *name)
{
	char *p = scpy(buf, root);
	p = scpy(p, "/basic/");
	p = scpy(p, name);
	return buf;
}

#define NTESTS (int)(sizeof(basic_tests)/sizeof(basic_tests[0]))

void _start(void)
{
	char path[128];

	puts("=== NoobKernel AutoInit ===\n");

	for (int l = 0; libc_roots[l]; l++) {
		const char *root = libc_roots[l];

		/* run each libc group in a fresh child process so dentry
		 * refcount churn from one group does not affect the next */
		long pid = sc(NR_clone, 0, 0, 0, 0, 0);
		if (pid == 0) {
			/* child: chdir to <root>/basic, run tests, exit */
			sc(NR_chdir, (long)root, 0, 0, 0, 0);
			sc(NR_chdir, (long)"basic", 0, 0, 0, 0);

			puts("#### OS COMP TEST GROUP START basic-");
			puts(root + 1);
			puts(" ####\n");

			for (int i = 0; i < NTESTS; i++) {
				/* pass basename — CWD already at <root>/basic */
				mkpath(path, root, basic_tests[i].name);
				if (basic_tests[i].enabled) {
					if (strncmp(basic_tests[i].name, "execve_", 7) == 0) {
						run_execve_variant(root, basic_tests[i].name);
					} else {
						puts("  run: "); puts(path); puts("\n");
						run(path);
					}
				} else {
					puts("  skip: "); puts(path); puts("\n");
				}
			}

			puts("#### OS COMP TEST GROUP END basic-");
			puts(root + 1);
			puts(" ####\n\n");
			sc(NR_exit, 0, 0, 0, 0, 0);
		}

		/* parent: wait for group child to finish */
		if (pid > 0) {
			int s = 0;
			sc(NR_wait4, pid, (long)&s, 0, 0, 0);
		}
	}

	puts("=== Done ===\n");
	sc(NR_shutdown,0,0,0,0,0);
	while(1);
}

static inline long syscall(long n, long a0, long a1, long a2, long a3)
{
	register long a7 asm("a7") = n;
	register long a0_r asm("a0") = a0;
	register long a1_r asm("a1") = a1;
	register long a2_r asm("a2") = a2;
	register long a3_r asm("a3") = a3;
	asm volatile("ecall" : "+r"(a0_r)
		     : "r"(a1_r), "r"(a2_r), "r"(a3_r), "r"(a7));
	return a0_r;
}

#define SYS_write    64
#define SYS_read     63
#define SYS_openat   56
#define SYS_close    57
#define SYS_exit     93
#define SYS_getpid   172
#define SYS_clone    220
#define SYS_execve   221
#define SYS_wait4    260
#define SYS_pipe2    59
#define SYS_kill     129
#define SYS_rt_sigaction 134
#define SYS_shutdown 500

#define sys_write(fd, buf, len)  syscall(SYS_write, (fd), (long)(buf), (len), 0)
#define sys_read(fd, buf, len)   syscall(SYS_read, (fd), (long)(buf), (len), 0)
#define sys_close(fd)            syscall(SYS_close, (fd), 0, 0, 0)
#define sys_exit(s)              syscall(SYS_exit, (s), 0, 0, 0)
#define sys_fork()               syscall(SYS_clone, 0, 0, 0, 0)
#define sys_exec(path)           syscall(SYS_execve, (long)(path), 0, 0, 0)
#define sys_wait(s)              syscall(SYS_wait4, (long)(s), 0, 0, 0)
#define sys_pipe(fds)            syscall(SYS_pipe2, (long)(fds), 0, 0, 0)
#define sys_kill(pid, sig)       syscall(SYS_kill, (pid), (sig), 0, 0)
#define sys_sigaction(sig, fn)   syscall(SYS_rt_sigaction, (sig), (long)(fn), 0, 0)
#define sys_shutdown()           syscall(SYS_shutdown, 0, 0, 0, 0)
#define sys_shutdown()          syscall(SYS_shutdown, 0, 0, 0, 0)

#define SIGKILL 9
#define SIGUSR1 10

static void puts(const char *s)
{
	while (*s)
		sys_write(1, s++, 1);
}

static void putc(char c)
{
	sys_write(1, &c, 1);
}

static char getc(void)
{
	char c;
	if (sys_read(0, &c, 1) < 0)
		return 0;
	return c;
}

static int strcmp(const char *a, const char *b)
{
	while (*a && *a == *b) {
		a++;
		b++;
	}
	return *(unsigned char *)a - *(unsigned char *)b;
}

static void readline(char *buf, int max)
{
	int pos = 0;
	while (pos < max - 1) {
		char c = getc();
		if (c == '\r')
			c = '\n';
		if (c == '\n') {
			putc('\n');
			buf[pos] = 0;
			return;
		}
		if (c == '\b' || c == 127) {
			if (pos > 0) {
				pos--;
				puts("\b \b");
			}
			continue;
		}
		buf[pos++] = c;
		putc(c);
	}
	buf[pos] = 0;
}

static volatile int sigusr1_flag;

static void sigusr1_handler(int sig)
{
	sigusr1_flag = 1;
	puts("SIGUSR1!\n");
}

void _start(void)
{
	char cmd[128];
	char path[128];

	puts("\n");
	puts("  ___   ___   ___ _  __           _             \n");
	puts(" / _ \\ / _ \\ / __| |/ /___ _ _ __| |_____ _ _  \n");
	puts("| (_) | (_) | (__| ' < / -_) '_/ _` / -_) ' \\ \n");
	puts(" \\___/ \\___/ \\___|_|\\_\\___|_| \\__,_\\___|_||_|\n");
	puts("                                                 \n");

	while (1) {
		puts("NoobShell$ ");

		readline(cmd, sizeof(cmd));

		if (cmd[0] == 0)
			continue;

		if (strcmp(cmd, "exit") == 0)
			sys_shutdown();

		if (strcmp(cmd, "help") == 0) {
			puts("Available commands: help, exit, pipedemo\n");
			puts("Run a program by typing its path (e.g. /hello.txt)\n");
			continue;
		}

		if (strcmp(cmd, "pipedemo") == 0) {
			int fds[2];
			if (sys_pipe(fds) < 0) {
				puts("pipe failed\n");
				continue;
			}
			int pid = sys_fork();
			if (pid < 0) {
				puts("fork failed\n");
				continue;
			}
			if (pid == 0) {
				char buf[64];
				int n = sys_read(fds[0], buf, sizeof(buf) - 1);
				if (n > 0) {
					buf[n] = 0;
					puts(buf);
					puts("\n");
				}
				sys_exit(0);
			}
			char msg[] = "Hello pipe!";
			sys_write(fds[1], msg, sizeof(msg) - 1);
			sys_wait(0);
			continue;
		}

		if (strcmp(cmd, "sigdemo") == 0) {
			sys_sigaction(SIGUSR1, sigusr1_handler);
			int pid = sys_fork();
			if (pid < 0) {
				puts("fork failed\n");
				continue;
			}
			if (pid == 0) {
				for (volatile long i = 0; i < 200000000; i++)
					;
				if (sigusr1_flag)
					puts("sigdemo ok\n");
				else
					puts("sigdemo fail\n");
				sys_exit(0);
			}
			sys_kill(pid, SIGUSR1);
			sys_wait(0);
			continue;
		}

		if (strcmp(cmd, "sigpipe") == 0) {
			sys_sigaction(SIGUSR1, sigusr1_handler);
			int fds[2];
			sys_pipe(fds);
			int pid = sys_fork();
			if (pid < 0) continue;
			if (pid == 0) {
				sys_close(fds[1]);
				char buf[8];
				sys_read(fds[0], buf, 1);
				if (sigusr1_flag)
					puts("sigpipe ok\n");
				else
					puts("sigpipe fail\n");
				sys_exit(0);
			}
			sys_close(fds[0]);
			for (volatile long i = 0; i < 50000000; i++);
			sys_kill(pid, SIGUSR1);
			sys_wait(0);
			continue;
		}

		int i = 0;
		while (cmd[i] && cmd[i] != ' ')
			i++;
		cmd[i] = 0;

		if (cmd[0] != '/') {
			path[0] = '/';
			int j, k;
			for (j = 0, k = 1; cmd[j]; j++, k++)
				path[k] = cmd[j];
			path[k] = 0;
		} else {
			for (i = 0; cmd[i]; i++)
				path[i] = cmd[i];
			path[i] = 0;
		}

		int pid = sys_fork();
		if (pid == 0) {
			int ret = sys_exec(path);
			if (ret < 0) {
				puts("exec failed: ");
				puts(path);
				puts("\n");
			}
			sys_exit(1);
		} else if (pid > 0) {
			sys_wait(0);
		} else {
			puts("fork failed\n");
		}
	}
}

/* UART character device — provides stdin/stdout/stderr backing via VFS.
 *
 * The file's f_inode is NULL so file_read()/file_write() skip the VFS layer
 * and call f_op->read/f_op->write directly (see src/fs/file.c:136).
 */
#include <fs/uartdev.h>
#include <hal/uart.h>
#include <sync/spinlock.h>
#include <mm/kalloc.h>

static int uartdev_open(struct inode *inode, struct file *file)
{
	(void)inode;
	(void)file;
	return 0;
}

static int uartdev_release(struct inode *inode, struct file *file)
{
	(void)inode;
	(void)file;
	return 0;
}

/* Non-blocking single-char read from the UART ring buffer.
 * Returns 0 (EOF) when the buffer is empty. */
static ssize_t uartdev_read(struct file *file, void *buf, size_t count,
			    loff_t *pos)
{
	(void)file;
	(void)pos;
	if (count == 0)
		return 0;

	spinlock_acquire(&uart_lock);
	if (uart_rbuf.head == uart_rbuf.tail) {
		spinlock_release(&uart_lock);
		return 0; /* no data available */
	}
	char c = uart_rbuf.buf[uart_rbuf.tail];
	uart_rbuf.tail = (uart_rbuf.tail + 1) % UART_RBUF_SIZE;
	spinlock_release(&uart_lock);

	*(char *)buf = c;
	return 1;
}

/* Write bytes directly to the UART transmitter. */
static ssize_t uartdev_write(struct file *file, const void *buf, size_t count,
			     loff_t *pos)
{
	(void)file;
	(void)pos;
	const char *p = buf;
	for (size_t i = 0; i < count; i++)
		uart_putchar(p[i]);
	return count;
}

static struct file_operations uart_fops = {
	.open    = uartdev_open,
	.release = uartdev_release,
	.read    = uartdev_read,
	.write   = uartdev_write,
};

struct file *uartdev_alloc_file(int flags)
{
	struct file *f = file_alloc();
	if (!f)
		return NULL;

	f->f_inode  = NULL;
	f->f_dentry = NULL;
	f->f_op     = &uart_fops;
	f->f_flags  = flags;
	f->f_mode   = 0; /* not a regular file or directory */

	/* call open() so the VFS open path is exercised */
	if (f->f_op && f->f_op->open) {
		if (f->f_op->open(NULL, f) < 0) {
			file_free(f);
			return NULL;
		}
	}

	return f;
}

