static int uvmcopy(pagetable_t old, pagetable_t new, uintptr_t start,
		   uintptr_t end)
{
	for (uintptr_t va = start; va < end; va += PAGE_SIZE) {
		pte_t *pte = va2pte(old, va, false);
		if (!pte || !(*pte & PTE_M))
			continue;

		uintptr_t pa = PTE2PA(*pte);
		int perm = PTE_FLAGS(*pte) & ~PTE_M;

		void *new_page = kzalloc_page();
		if (!new_page)
			return -ENOMEM;
		memcpy(new_page, (void *)pa, PAGE_SIZE);

		if (mappages(new, va, (uintptr_t)new_page, 1,
			     perm | PTE_M | PTE_V)) {
			kfree_page(new_page);
			return -ENOMEM;
		}
	}
	return 0;
}

int64_t sys_clone(void)
{
	struct proc *p = thiscpu()->proc;
	int flags = arg_int(0);
	uintptr_t child_tidp = arg_ptr(4);

	struct proc *np = alloc_proc();
	if (!np)
		return -ENOMEM;

	np->pid = alloc_pid();
	np->tgid = p->tgid;
	strncpy(np->comm, p->comm, sizeof(np->comm));
	np->lock = SPINLOCK_INITIALIZER(np->comm);

	np->kstack = buddy_alloc(PAGE_SIZE * 4);
	if (!np->kstack) {
		free_proc(np);
		return -ENOMEM;
	}
	/* stack overflow guard: magic at bottom of kstack */
	*(u32 *)np->kstack = 0xDEADBEEF;
	*(u32 *)((u8 *)np->kstack + 4) = 0xDEADBEEF;
	np->ctx.gp = (uintptr_t)&np->ktf;
	np->ctx.sstatus = SSTATUS_SIE;
	np->ctx.ra = (uintptr_t)usertrapret;

	np->pagetable = pagetable_create();
	if (!np->pagetable) {
		free_proc(np);
		return -ENOMEM;
	}

	if (uvmcopy(p->pagetable, np->pagetable, 0, USER_TOP)) {
		free_proc(np);
		return -ENOMEM;
	}

	uintptr_t tramp_pa = walkaddr(kpagetable, TRAMPOLINE);
	if (mappages(np->pagetable, TRAMPOLINE, tramp_pa, 1,
		     PTE_R | PTE_X | PTE_V)) {
		free_proc(np);
		return -ENOMEM;
	}

	uintptr_t sigtramp_pa = walkaddr(kpagetable, SIGNAL_TRAMPOLINE);
	if (mappages(np->pagetable, SIGNAL_TRAMPOLINE, sigtramp_pa, 1,
		     PTE_R | PTE_X | PTE_U | PTE_V)) {
		free_proc(np);
		return -ENOMEM;
	}

	for (int i = 0; i < NSIG; i++)
		np->sighandlers[i] = p->sighandlers[i];
	np->sig_blocked = p->sig_blocked;
	np->sig_pending = 0;
	np->in_signal_handler = false;

	struct trapframe *ntf = kzalloc_page();
	if (!ntf) {
		free_proc(np);
		return -ENOMEM;
	}
	memcpy(ntf, p->tf, sizeof(struct trapframe));
	// errorf("TRAPFRAME: pid=%d tf_pa=%p (cloned from pid=%d)",
	//        np->pid, ntf, p->pid);

	uintptr_t ntf_pa = (uintptr_t)ntf;
	if (mappages(np->pagetable, TRAPFRAME, ntf_pa, 1,
		     PTE_R | PTE_W | PTE_V)) {
		kfree_page(ntf);
		free_proc(np);
		return -ENOMEM;
	}
	np->tf = ntf;
	uintptr_t child_stack = arg_ptr(1);
	if (child_stack)
		np->tf->sp = child_stack;
	np->tf->a0 = 0;
	np->tf->epc += 4;

	u64 stack_top = (u64)np->kstack + KSTACK_SIZE;
	stack_top &= ~0xFULL;
	np->ctx.sp = stack_top;

	fd_table_free(np->fd_table);
	np->fd_table = fd_table_dup(p->fd_table);
	if (!np->fd_table) {
		free_proc(np);
		return -ENOMEM;
	}

	spinlock_acquire(&p->lock);
	np->parent = p;
	list_add_tail(&np->sibling, &p->children);
	spinlock_release(&p->lock);

	np->pwd = p->pwd;
	if (np->pwd)
		dentry_get(np->pwd);

	np->state = PROC_RUNNABLE;
	enqueue_proc(r_tp(), np);


	if (flags & 0x01000000) { /* CLONE_CHILD_SETTID */
		np->child_tidp = child_tidp;
		int pid = np->pid;
		copyout(np->pagetable, child_tidp, &pid, sizeof(pid));
	}

	return np->pid;
}

