	uintptr_t sp = create_elf_tables(p->pagetable,
					 argc, argv_saved,
					 envc, envp_saved,
					 &info, interp_base, path);

	/* ── 9. set trapframe for user-space entry ── */
	p->tf->epc = (interp_base && info.has_interp) ? info.interp_entry
