	/* ── 11. reset signal handlers ── */
	for (int i = 0; i < NSIG; i++)
		p->sighandlers[i] = (void (*)(int))0;
	p->sig_blocked = 0;
	p->sig_pending = 0;

	return 0;
}

int64_t sys_wait4(void)
{
	struct proc *p = thiscpu()->proc;
	int target_pid = arg_int(0);
	uintptr_t status_va = arg_ptr(1);
	int options = arg_int(2);

	while (1) {
		struct list_head *pos, *n;
		list_for_each_safe(pos, n, &p->children)
		{
			struct proc *child =
			    list_entry(pos, struct proc, sibling);
			if (child->state == PROC_ZOMBIE &&
			    (target_pid == -1 || target_pid == child->pid)) {
				int pid = child->pid;
				int exit_code = child->exit_code;
				if (status_va) {
					if (copyout(p->pagetable, status_va,
						    &exit_code,
						       sizeof(exit_code))) {
						list_del(&child->sibling);
						return -EFAULT;
					}
				}
				list_del(&child->sibling);
				// errorf("wait4: pid=%d returning child pid=%d",
				//        p->pid, pid);
				return pid;
			}
		}

		if (list_empty(&p->children))
			return -ECHILD;

		if (options & 1) /* WNOHANG */
			return 0;

		// errorf("wait4: pid=%d sleeping on chan=%p",
		//        p->pid, p);

		/* Save trapframe checksum for pid=2 before sleeping.
		 * Any write to the trapframe page will change the checksum. */
		u32 tf_cksum = 0;
		if (p->pid == 2 && p->tf)
			for (int i = 0; i < 256; i++)
				tf_cksum += ((u8 *)p->tf)[i];

		p->state = PROC_SLEEPING;
		p->chan = p;
		sched_yield();

		/* Verify trapframe integrity after waking */
		if (p->pid == 2 && p->tf) {
			u32 ck = 0;
			for (int i = 0; i < 256; i++)
				ck += ((u8 *)p->tf)[i];
			if (ck != tf_cksum)
				panic("TRAPFRAME OVERWRITTEN during sleep! "
				      "cksum before=%x after=%x",
				      tf_cksum, ck);
		}

		// errorf("wait4: pid=%d woke up", p->pid);
	}
}

