int64_t sys_getcwd(void)
{
	struct proc *p = thiscpu()->proc;
	uintptr_t ubuf = arg_ptr(0);
	size_t size = arg_size(1);

	if (size < 2 || ubuf < USER_BASE)
		return -EINVAL;

	struct dentry *dentry = p->pwd;
	if (!dentry)
		return -ENOENT;

	dentry_get(dentry);

	int depth = 0;
	struct dentry *d = dentry;
	while (d && d->d_parent && d != d->d_parent) {
		depth++;
		d = d->d_parent;
	}

	if (depth > 63) {
		dentry_put(dentry);
		return -ENAMETOOLONG;
	}

	const char *components[64];
	d = dentry;
	for (int i = depth - 1; i >= 0; i--) {
		components[i] = d->d_name.name;
		d = d->d_parent;
	}

	char path[PATH_MAX];
	int off = 0;
	path[off++] = '/';
	for (int i = 0; i < depth; i++) {
		int len = 0;
		while (components[i][len])
			len++;
		if (off + len + 1 > PATH_MAX) {
			dentry_put(dentry);
			return -ENAMETOOLONG;
		}
		if (i > 0)
			path[off++] = '/';
		memcpy(path + off, components[i], len);
		off += len;
	}
	path[off] = '\0';

	dentry_put(dentry);

	off++;
	if ((size_t)off > size)
		return -ERANGE;

	return copyout(p->pagetable, ubuf, path, off) ? -EFAULT : off;
}

int64_t sys_chdir(void)
{
	struct proc *p = thiscpu()->proc;
	char path[256];
	int err = fetch_str(path, 0, sizeof(path));
	if (err < 0)
		return err;

	struct dentry *d = vfs_path_lookup(p->pwd, path, 0);
	if (!d || (unsigned long)d >= (unsigned long)-MAX_ERRNO)
		return -ENOENT;
	if (!d->d_inode || !S_ISDIR(d->d_inode->i_mode)) {
		dentry_put(d);
		return -ENOTDIR;
	}

	dentry_put(p->pwd);
	p->pwd = d;
	/* vfs_path_lookup already bumped d->d_refcnt; no extra get needed */
	return 0;
}

