char *strtok(char *str, const char *delim) {
  static char *last = NULL;
  char *token;

  if (str) {
    last = str;
  } else if (!last) {
    return NULL;
  }

  // 跳过前导分隔符
  while (*last && strchr(delim, *last)) {
    last++;
  }

  if (!*last) {
    last = NULL;
    return NULL;
  }

  token = last;

  // 找到下一个分隔符
  while (*last && !strchr(delim, *last)) {
    last++;
  }

  if (*last) {
    *last = '\0';
    last++;
  } else {
    last = NULL;
  }

  return token;
}

